DROP TABLE IF EXISTS `cache_locks`;
CREATE TABLE `cache_locks` (`key` VARCHAR(255) not null, `owner` VARCHAR(255) not null, `expiration` integer not null, primary key (`key`));

DROP TABLE IF EXISTS `jobs`;
CREATE TABLE `jobs` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `queue` VARCHAR(255) not null, `payload` text not null, `attempts` integer not null, `reserved_at` integer, `available_at` integer not null, `created_at` integer not null);

DROP TABLE IF EXISTS `job_batches`;
CREATE TABLE `job_batches` (`id` VARCHAR(255) not null, `name` VARCHAR(255) not null, `total_jobs` integer not null, `pending_jobs` integer not null, `failed_jobs` integer not null, `failed_job_ids` text not null, `options` text, `cancelled_at` integer, `created_at` integer not null, `finished_at` integer, primary key (`id`));

DROP TABLE IF EXISTS `failed_jobs`;
CREATE TABLE `failed_jobs` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `uuid` VARCHAR(255) not null, `connection` text not null, `queue` text not null, `payload` text not null, `exception` text not null, `failed_at` datetime not null default CURRENT_TIMESTAMP);

DROP TABLE IF EXISTS `heroes`;
CREATE TABLE `heroes` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `subtitle` text not null, `image` VARCHAR(255) not null, `button_text` VARCHAR(255), `button_link` VARCHAR(255), `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);

INSERT INTO `heroes` (`id`, `title`, `subtitle`, `image`, `button_text`, `button_link`, `is_active`, `created_at`, `updated_at`) VALUES ('1', 'Selamat Datang di PII', 'Persatuan Insinyur Indonesia - Wadah persatuan dan kesatuan insinyur Indonesia untuk memajukan profesi keinsinyuran dan berkontribusi bagi pembangunan bangsa.', 'uploads/heroes/1778384523.jpg', NULL, NULL, '1', '2026-05-10 02:47:45', '2026-05-12 01:21:38');
INSERT INTO `heroes` (`id`, `title`, `subtitle`, `image`, `button_text`, `button_link`, `is_active`, `created_at`, `updated_at`) VALUES ('2', 'tesss', 'tesssssssssssssssssss', 'uploads/heroes/1778384721.png', NULL, NULL, '1', '2026-05-10 03:45:21', '2026-05-12 01:21:38');
INSERT INTO `heroes` (`id`, `title`, `subtitle`, `image`, `button_text`, `button_link`, `is_active`, `created_at`, `updated_at`) VALUES ('3', 'Selamat Datang di PII', 'Persatuan Insinyur Indonesia - Wadah persatuan dan kesatuan insinyur Indonesia untuk memajukan profesi keinsinyuran dan berkontribusi bagi pembangunan bangsa.', 'https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=1920', 'tes', 'https://facebook.com', '1', '2026-05-11 03:11:09', '2026-05-13 06:29:48');

DROP TABLE IF EXISTS `sejarahs`;
CREATE TABLE `sejarahs` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `content` text not null, `image` VARCHAR(255), `image_path` VARCHAR(255), `period` VARCHAR(255), `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);

INSERT INTO `sejarahs` (`id`, `title`, `content`, `image`, `image_path`, `period`, `is_active`, `created_at`, `updated_at`) VALUES ('1', 'Sejarah PII', '<p class=\"leading-7 py-1\" dir=\"ltr\">Persatuan Insinyur Indonesia (PII) didirikan tanggal 23 Mei 1952 di Kota Bandung oleh Djoeanda Kartawidjaja dan Roosseno Soerjohadikoesoemo atas prakarsa Presiden Soekarno. Jumlah anggota PII pada saat didirikan adalah 75 orang.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Pendirian PII ditujukan untuk mendukung proses pembangunan Indonesia pasca-kemerdekaan. Saat itu, para insinyur memiliki peran strategis dalam pembangunan infrastruktur dan pengembangan teknologi yang dibutuhkan oleh negara yang baru merdeka.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\"><strong class=\"font-bold\">Profil Ir. H. Raden Djoeanda Kartawidjaja</strong></p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Kelahiran Tasikmalaya, alumni Technische Hoogeschool te Bandoeng (THS). Pernah menjabat sebagai Perdana Menteri Indonesia tahun 1957-1959.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Sumbangan terbesarnya adalah Deklarasi Djuanda tahun 1957 yang menyatakan bahwa laut Indonesia adalah termasuk laut sekitar, di antara dan di dalam kepulauan Indonesia menjadi satu kesatuan wilayah NKRI, atau dikenal dengan sebutan sebagai negara kepulauan dalam konvensi hukum laut UNCLOS.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\"><strong class=\"font-bold\">Profil Prof. Dr. Ir. Roosseno Soerjohadikoesoemo</strong></p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Kelahiran Madiun, alumni Technische Hoogeschool te Bandoeng (THS). Mengawali karier dengan berwiraswasta di Bandung dengan mendirikan Biro Insinyur Roosseno dan Soekarno (Presiden pertama RI) di Jalan Banceuy pada tahun 1933.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Merupakan profesor pribumi pertama di jurusan Teknik Sipil ITB pada tahun 1948 dan dikenal sebagai Bapak Beton Indonesia. Beliau juga tercatat sebagai salah seorang pendiri Fakultas Teknik Universitas Gadjah Mada di Yogyakarta. id</p>', 'uploads/sejarah/1778405869.jpg', 'uploads/sejarah/1778405869.jpg', NULL, '1', '2026-05-10 08:20:10', '2026-05-12 01:21:38');

DROP TABLE IF EXISTS `sekilas`;
CREATE TABLE `sekilas` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `content` text not null, `image` VARCHAR(255), `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);

INSERT INTO `sekilas` (`id`, `title`, `content`, `image`, `is_active`, `created_at`, `updated_at`) VALUES ('1', 'Sekilas PII', '<p class=\"leading-7 py-1\" dir=\"ltr\">Persatuan Insinyur Indonesia (PII) adalah organisasi profesi yang mewadahi para insinyur dari berbagai disiplin teknik di seluruh Indonesia. Awalnya beranggotakan 75 orang, PII kini berkembang pesat dan memiliki sekitar 90.000 insinyur yang tergabung dalam 280 cabang di tingkat kabupaten/kota, 30 wilayah di tingkat provinsi, serta x Badan Kejuruan dan Badan Kejuruan Teknik.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Sesuai dengan amanat Undang-Undang No. 11 Tahun 2014 tentang Keinsinyuran, PII diberikan mandat sebagai Lembaga Sertifikasi Profesi Keinsinyuran dan sebagai organisasi yang berwenang melakukan registrasi insinyur. Undang-undang tersebut menyatakan bahwa setiap insinyur yang akan menjalankan praktik keinsinyuran wajib memiliki Sertifikat Kompetensi Insinyur Profesional (SKIP) yang diterbitkan oleh PII, serta terdaftar di kementerian terkait melalui sistem yang ditetapkan bersama.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Ini menunjukkan bahwa PII memiliki peran strategis dalam menjaga kualitas praktik keinsinyuran di Indonesia, sekaligus memastikan keselamatan, keberlanjutan, dan akuntabilitas dalam setiap proyek teknis.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\">PII juga aktif dalam menjalin kerja sama dengan lembaga internasional seperti WFEO (World Federation of Engineering Organizations) untuk memperkuat daya saing insinyur Indonesia di kancah global.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Lebih dari sekadar organisasi profesi, PII juga mengambil bagian dalam advokasi kebijakan publik yang terkait dengan pembangunan infrastruktur, energi, lingkungan, dan teknologi. Melalui kajian teknis dan rekomendasi berbasis ilmu pengetahuan, PII berkontribusi dalam pengambilan keputusan nasional yang berbasis pada prinsip keinsinyuran yang berkelanjutan dan beretika.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Saat ini PII secara aktif terlibat dalam berbagai inisiatif untuk mendorong re-industrialisasi Indonesia menuju Indonesia Emas 2045.</p>', 'uploads/sekilas/1778502289.jpg', '1', '2026-05-11 12:24:49', '2026-05-12 01:21:38');

DROP TABLE IF EXISTS `struktur_organisasis`;
CREATE TABLE `struktur_organisasis` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime, `title` VARCHAR(255), `content` text, `image` VARCHAR(255));

INSERT INTO `struktur_organisasis` (`id`, `is_active`, `created_at`, `updated_at`, `title`, `content`, `image`) VALUES ('1', '1', '2026-05-12 09:35:34', '2026-05-13 14:43:10', 'Struktur Organisasi', '<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Ketua Umum:</strong>&nbsp;Dr.-Ing.Ir. Ilham Akbar Habibie, MBA., IPU.</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Wakil Ketua Umum:</strong>&nbsp;Prof. Dr. Ir. Agus Taufik Mulyono, ST., MT., IPU., ASEAN Eng.</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Kepala Satuan Pengawas Internal:</strong>&nbsp;Dr. Ir. Abdullah Qiqi Asmara, S.T., M.Si., M.Kom., IPU</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Sekretaris Jendral:</strong>&nbsp;Dr. Ir. Teguh Haryono, MBA., IPU., ACPE., ASEAN Eng., APEC Eng.</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Bendahara Umum:</strong>&nbsp;Ir. Hilmi Panigoro, MBA., MSc</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Direktur Eksekutif:</strong>&nbsp;Ir. Santhi H. Serad, M.Sc., IPU.</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Wakil Sekretaris Jenderal</strong></p>
<ol class=\"my-1 pl-6 list-decimal [&amp;&gt;li]:mt-2 [&amp;&gt;li]:text-sm list-outside !list-decimal\">
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"1\">Wakil Sekretaris Jenderal 1: Ir. Sri Hidayat AKP, ST, M.Sc(PM)., IPU, APEC Eng., ASEAN Eng.</li>
