DROP TABLE IF EXISTS `artikels`;
CREATE TABLE `artikels` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `category` VARCHAR(255) not null, `author` VARCHAR(255) not null, `excerpt` text not null, `content` text, `image` VARCHAR(255) not null, `published_at` datetime, `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);

DROP TABLE IF EXISTS `galleries`;
CREATE TABLE `galleries` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `image` VARCHAR(255) not null, `description` text, `category` VARCHAR(255), `order` integer not null default '0', `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);

