DROP TABLE IF EXISTS `beritas`;
CREATE TABLE `beritas` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `author` VARCHAR(255) not null, `excerpt` text not null, `content` text, `image` VARCHAR(255), `published_at` datetime, `is_active` tinyint(1) not null default ('1'), `created_at` datetime, `updated_at` datetime, `category` VARCHAR(255), `sub_category` VARCHAR(255));

INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('1', 'PII Gelar Kongres Nasional Ke-32 di Jakarta', 'Humas PII', 'Persatuan Insinyur Indonesia sukses menyelenggarakan Kongres Nasional ke-32 yang dihadiri oleh lebih dari 500 insinyur dari seluruh Indonesia. Acara i...', '<p>Persatuan Insinyur Indonesia sukses menyelenggarakan Kongres Nasional ke-32 yang dihadiri oleh lebih dari 500 insinyur dari seluruh Indonesia. Acara ini membahas berbagai isu strategis terkait pembangunan nasional dan peran insinyur dalam era digital.</p>', 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800', '2026-05-08 02:47:45', '1', '2026-05-10 02:47:45', '2026-05-11 02:31:19', 'artikel_teknik', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('8', 'PII Gelar Kongres Nasional Ke-32 di Jakarta', 'Humas PII', 'Persatuan Insinyur Indonesia sukses menyelenggarakan Kongres Nasional ke-32 yang dihadiri oleh lebih dari 500 insinyur dari seluruh Indonesia.', '<p>Persatuan Insinyur Indonesia sukses menyelenggarakan Kongres Nasional ke-32 yang dihadiri oleh lebih dari 500 insinyur dari seluruh Indonesia. Acara ini membahas berbagai isu strategis terkait pembangunan nasional dan peran insinyur dalam era digital.</p><p>Kongres yang berlangsung selama tiga hari ini menghasilkan beberapa rekomendasi penting untuk pengembangan profesi keinsinyuran di Indonesia. Para peserta aktif berdiskusi tentang tantangan dan peluang yang dihadapi oleh insinyur Indonesia di era globalisasi.</p><p>\"Kita harus memastikan bahwa insinyur Indonesia siap menghadapi revolusi industri 4.0. Ini bukan lagi tentang pilihan, tapi keharusan,\" ujar Ketua Umum PII dalam sambutannya.</p>', 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800', '2026-05-09 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'artikel_teknik', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('9', 'Peluncuran Program Sertifikasi Baru untuk Insinyur Muda', 'Divisi Pendidikan', 'PII meluncurkan program sertifikasi baru yang dirancang khusus untuk insinyur muda untuk meningkatkan daya saing di pasar kerja.', '<p>PII meluncurkan program sertifikasi baru yang dirancang khusus untuk insinyur muda untuk meningkatkan daya saing di pasar kerja. Program ini mencakup berbagai kompetensi teknis dan soft skills yang dibutuhkan di industri 4.0.</p><p>Program sertifikasi ini terdiri dari beberapa level, mulai dari junior engineer hingga professional engineer. Setiap level memiliki kriteria dan standar kompetensi yang harus dipenuhi oleh peserta.</p><p>\"Dengan adanya program ini, kami berharap dapat meningkatkan kualitas insinyur Indonesia secara menyeluruh,\" jelas Direktur Pendidikan PII.</p>', 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?w=800', '2026-05-06 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'regulasi', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('10', 'Kerjasama PII dengan Berbagai Universitas', 'Kerjasama Luar Negeri', 'PII menjalin kerjasama strategis dengan universitas-universitas terkemuka untuk pengembangan pendidikan keinsinyuran.', '<p>PII menjalin kerjasama strategis dengan universitas-universitas terkemuka untuk pengembangan pendidikan keinsinyuran. Kerjasama ini meliputi pertukaran mahasiswa, joint research, dan program magang.</p><p>Beberapa universitas yang telah menjalin kerjasama meliputi ITB, UI, UGM, dan ITS. Kerjasama ini diharapkan dapat menjembatani dunia akademik dengan dunia industri.</p><p>\"Kolaborasi antara perguruan tinggi dan organisasi profesi sangat penting untuk memastikan lulusan siap kerja,\" ujar salah satu dekan teknik yang hadir dalam penandatanganan MoU.</p>', 'https://images.unsplash.com/photo-1562774053-701939374585?w=800', '2026-05-04 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'inovasi', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('11', 'Seminar Nasional Teknologi Hijau 2024', 'Panitia Seminar', 'Seminar nasional yang membahas inovasi teknologi hijau untuk mendukung pembangunan berkelanjutan di Indonesia.', '<p>Seminar nasional yang membahas inovasi teknologi hijau untuk mendukung pembangunan berkelanjutan di Indonesia. Hadirkan pembicara ahli dari dalam dan luar negeri.</p><p>Teknologi hijau menjadi fokus utama dalam seminar ini, mengingat komitmen Indonesia untuk mengurangi emisi karbon. Berbagai solusi inovatif dari insinyur Indonesia dipresentasikan dalam acara ini.</p><p>\"Insinyur memiliki peran penting dalam menciptakan solusi teknologi yang ramah lingkungan,\" tegas salah satu pembicara kunci.</p>', 'https://images.unsplash.com/photo-1497436072909-60f360e1d4b1?w=800', '2026-05-01 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'inovasi', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('12', 'Beasiswa PII untuk Mahasiswa Teknik', 'Divisi Beasiswa', 'PII membuka program beasiswa untuk mahasiswa teknik berprestasi dari seluruh Indonesia untuk tahun akademik 2024/2025.', '<p>PII membuka program beasiswa untuk mahasiswa teknik berprestasi dari seluruh Indonesia untuk tahun akademik 2024/2025. Beasiswa ini mencakup biaya pendidikan dan dukungan pengembangan karir.</p><p>Program beasiswa ini terbuka untuk mahasiswa semester 3-7 dari berbagai disiplin teknik. Seleksi dilakukan berdasarkan prestasi akademik, aktivitas organisasi, dan wawancara.</p><p>\"Kami berkomitmen untuk mendukung generasi muda Indonesia yang berbakat di bidang teknik,\" ungkap Ketua Divisi Beasiswa PII.</p>', 'https://images.unsplash.com/photo-1427504494785-3a9ca7044f45?w=800', '2026-04-27 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'artikel_teknik', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('13', 'Perubahan Regulasi Sertifikat Kompetensi Insinyur 2024', 'Divisi Regulasi', 'Pemerintah mengeluarkan regulasi baru terkait sertifikat kompetensi insinyur yang berlaku mulai tahun 2024.', '<p>Pemerintah melalui Kementerian PUPR mengeluarkan regulasi baru terkait sertifikat kompetensi insinyur yang berlaku mulai tahun 2024. Regulasi ini membawa beberapa perubahan signifikan dalam proses sertifikasi.</p><p>Beberapa poin penting dalam regulasi baru meliputi: penambahan kompetensi digital, peningkatan standar keselamatan, dan adopsi standar internasional.</p><p>PII menyambut baik regulasi ini dan berkomitmen untuk membantu anggota dalam proses transisi menuju sistem yang baru.</p>', 'https://images.unsplash.com/photo-1450101499163-c8848c66ca85?w=800', '2026-05-03 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'regulasi', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('14', 'Inovasi AI dalam Perencanaan Proyek Konstruksi', 'Divisi Teknologi', 'Pemanfaatan kecerdasan buatan (AI) semakin merambah ke dunia konstruksi, membawa efisiensi yang signifikan.', '<p>Pemanfaatan kecerdasan buatan (AI) semakin merambah ke dunia konstruksi, membawa efisiensi yang signifikan dalam perencanaan dan pelaksanaan proyek.</p><p>Beberapa perusahaan konstruksi besar di Indonesia telah mulai mengadopsi teknologi AI untuk optimasi jadwal, prediksi risiko, dan manajemen sumber daya.</p><p>\"AI bukan pengganti insinyur, tapi alat bantu yang sangat powerful untuk meningkatkan akurasi dan efisiensi,\" jelas pakar konstruksi yang menjadi narasumber.</p>', 'https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=800', '2026-05-08 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'inovasi', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('15', 'Masa Depan Profesi Insinyur di Era Digital', 'Prof. Dr. Ahmad Santoso', 'Refleksi tentang bagaimana profesi keinsinyuran harus beradaptasi dengan perkembangan teknologi digital.', '<p>Profesi keinsinyuran sedang menghadapi titik balik yang penting. Era digital tidak hanya mengubah cara kita bekerja, tapi juga mengubah esensi dari apa yang menjadi tanggung jawab seorang insinyur.</p><p>Di masa depan, insinyur tidak hanya dituntut untuk memahami fisika dan matematika, tapi juga harus menguasai data science, pemrograman, dan berbagai soft skills baru.</p><p>Adaptasi adalah kunci. Insinyur yang mampu menggabungkan pengetahuan teknik klasik dengan keterampilan digital akan menjadi pemimpin di era baru ini.</p>', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800', '2026-05-07 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'opini', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('17', 'Teknik Sipil dan Tantangan Perubahan Iklim', 'Ir. Budi Hartono, M.Eng', 'Perubahan iklim membawa tantangan baru bagi insinyur sipil dalam merancang infrastruktur yang tangguh.', '<p>Perubahan iklim bukan lagi isu abstrak. Bagi insinyur sipil, ini adalah realitas yang harus dihadapi setiap hari dalam bentuk cuaca ekstrem, kenaikan muka air laut, dan perubahan pola curah hujan.</p><p>Infrastruktur yang kita bangun 20 tahun lalu mungkin tidak cukup kuat menghadapi kondisi iklim saat ini. Ini berarti kita perlu merevisi banyak standar dan spesifikasi teknis.</p><p>Resilience menjadi kata kunci dalam setiap proyek konstruksi modern. Bangunan tidak hanya harus kuat, tapi juga adaptif terhadap perubahan lingkungan.</p>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800', '2026-05-02 03:11:09', '1', '2026-05-11 03:11:09', '2026-05-11 03:11:09', 'artikel_teknik', NULL);
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('18', 'Pelantikan dan Pengambilan Sumpah PSPPI Fakultas Teknik Universitas Katolik Widya Mandala Surabaya Tahun Akademik 2025/2026', 'Admin PII', 'Pelantikan dan Pengambilan Sumpah Profesi Insinyur Program Studi Program Profesi Insinyur (PSPPI) Fakultas Teknik Universitas Katolik Widya Mandala Su...', '<p>Pelantikan dan Pengambilan Sumpah Profesi Insinyur Program Studi Program Profesi Insinyur (PSPPI) Fakultas Teknik Universitas Katolik Widya Mandala Surabaya Tahun Akademik 2025/2026 telah dilaksanakan dengan khidmat pada sabtu, 18 April 2026.<br><br>Dalam kesempatan ini, Persatuan Insinyur Indonesia (PII) diwakili oleh Sekretaris Jenderal PII, Dr. Ir. Teguh Haryono, MBA., IPU., ASEAN Eng., ACPE., APEC Eng. yang hadir secara langsung.<br><br>Momentum ini menjadi tonggak penting bagi para lulusan dalam mengemban tanggung jawab sebagai insinyur profesional, sekaligus memperkuat komitmen dalam menjunjung tinggi etika dan kontribusi nyata bagi pembangunan bangsa.<br><br>Selamat kepada para insinyur baru, terus berkarya dan berkontribusi untuk Indonesia.<br><br><a class=\"text-blue-600 hover:underline hover:cursor-pointer\" dir=\"ltr\" href=\"https://www.instagram.com/explore/tags/pii/\">#PII</a>&nbsp;<a class=\"text-blue-600 hover:underline hover:cursor-pointer\" dir=\"ltr\" href=\"https://www.instagram.com/explore/tags/psppi/\">#PSPPI</a>&nbsp;<a class=\"text-blue-600 hover:underline hover:cursor-pointer\" dir=\"ltr\" href=\"https://www.instagram.com/explore/tags/insinyurindonesia/\">#InsinyurIndonesia</a>&nbsp;<a class=\"text-blue-600 hover:underline hover:cursor-pointer\" dir=\"ltr\" href=\"https://www.instagram.com/explore/tags/universitasmulawarman/\">#UniversitasMulawarman</a>&nbsp;<a class=\"text-blue-600 hover:underline hover:cursor-pointer\" dir=\"ltr\" href=\"https://www.instagram.com/explore/tags/engineering/\">#engineering</a></p>', 'uploads/beritas/1778476414.jpeg', '2026-05-11 05:13:34', '1', '2026-05-11 05:13:34', '2026-05-12 01:21:38', 'artikel_teknik', 'Pelantikan PSPPI');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('21', 'tes 2', 'Admin PII', 'tes 5', '<p>tes 5</p>', NULL, '2026-05-11 05:25:03', '1', '2026-05-11 05:25:03', '2026-05-11 05:25:03', 'inovasi', 'tes 5');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('23', 'PII Gelar Kongres Nasional Ke-32 di Jakarta', 'Humas PII', 'Persatuan Insinyur Indonesia sukses menyelenggarakan Kongres Nasional ke-32 yang dihadiri oleh lebih dari 500 insinyur dari seluruh Indonesia.', '<p>Persatuan Insinyur Indonesia sukses menyelenggarakan Kongres Nasional ke-32 yang dihadiri oleh lebih dari 500 insinyur dari seluruh Indonesia. Acara ini membahas berbagai isu strategis terkait pembangunan nasional dan peran insinyur dalam era digital.</p><p>Kongres yang berlangsung selama tiga hari ini menghasilkan beberapa rekomendasi penting untuk pengembangan profesi keinsinyuran di Indonesia. Para peserta aktif berdiskusi tentang tantangan dan peluang yang dihadapi oleh insinyur Indonesia di era globalisasi.</p><p>\"Kita harus memastikan bahwa insinyur Indonesia siap menghadapi revolusi industri 4.0. Ini bukan lagi tentang pilihan, tapi keharusan,\" ujar Ketua Umum PII dalam sambutannya.</p>', 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800&q=80', '2026-05-09 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'artikel_teknik', 'Kegiatan Nasional');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('24', 'Peluncuran Program Sertifikasi Baru untuk Insinyur Muda', 'Divisi Pendidikan', 'PII meluncurkan program sertifikasi baru yang dirancang khusus untuk insinyur muda untuk meningkatkan daya saing di pasar kerja.', '<p>PII meluncurkan program sertifikasi baru yang dirancang khusus untuk insinyur muda untuk meningkatkan daya saing di pasar kerja. Program ini mencakup berbagai kompetensi teknis dan soft skills yang dibutuhkan di industri 4.0.</p><p>Program sertifikasi ini terdiri dari beberapa level, mulai dari junior engineer hingga professional engineer. Setiap level memiliki kriteria dan standar kompetensi yang harus dipenuhi oleh peserta.</p><p>\"Dengan adanya program ini, kami berharap dapat meningkatkan kualitas insinyur Indonesia secara menyeluruh,\" jelas Direktur Pendidikan PII.</p>', 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?w=800&q=80', '2026-05-06 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regulasi', 'Sertifikasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('25', 'Kerjasama PII dengan Berbagai Universitas', 'Kerjasama Luar Negeri', 'PII menjalin kerjasama strategis dengan universitas-universitas terkemuka untuk pengembangan pendidikan keinsinyuran.', '<p>PII menjalin kerjasama strategis dengan universitas-universitas terkemuka untuk pengembangan pendidikan keinsinyuran. Kerjasama ini meliputi pertukaran mahasiswa, joint research, dan program magang.</p><p>Beberapa universitas yang telah menjalin kerjasama meliputi ITB, UI, UGM, dan ITS. Kerjasama ini diharapkan dapat menjembatani dunia akademik dengan dunia industri.</p><p>\"Kolaborasi antara perguruan tinggi dan organisasi profesi sangat penting untuk memastikan lulusan siap kerja,\" ujar salah satu dekan teknik yang hadir dalam penandatanganan MoU.</p>', 'https://images.unsplash.com/photo-1562774053-701939374585?w=800&q=80', '2026-05-04 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Kerjasama');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('26', 'Seminar Nasional Teknologi Hijau 2024', 'Panitia Seminar', 'Seminar nasional yang membahas inovasi teknologi hijau untuk mendukung pembangunan berkelanjutan di Indonesia.', '<p>Seminar nasional yang membahas inovasi teknologi hijau untuk mendukung pembangunan berkelanjutan di Indonesia. Hadirkan pembicara ahli dari dalam dan luar negeri.</p><p>Teknologi hijau menjadi fokus utama dalam seminar ini, mengingat komitmen Indonesia untuk mengurangi emisi karbon. Berbagai solusi inovatif dari insinyur Indonesia dipresentasikan dalam acara ini.</p><p>\"Insinyur memiliki peran penting dalam menciptakan solusi teknologi yang ramah lingkungan,\" tegas salah satu pembicara kunci.</p>', 'https://images.unsplash.com/photo-1497436072909-60f360e1d4b1?w=800&q=80', '2026-05-01 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Teknologi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('27', 'Beasiswa PII untuk Mahasiswa Teknik', 'Divisi Beasiswa', 'PII membuka program beasiswa untuk mahasiswa teknik berprestasi dari seluruh Indonesia untuk tahun akademik 2024/2025.', '<p>PII membuka program beasiswa untuk mahasiswa teknik berprestasi dari seluruh Indonesia untuk tahun akademik 2024/2025. Beasiswa ini mencakup biaya pendidikan dan dukungan pengembangan karir.</p><p>Program beasiswa ini terbuka untuk mahasiswa semester 3-7 dari berbagai disiplin teknik. Seleksi dilakukan berdasarkan prestasi akademik, aktivitas organisasi, dan wawancara.</p><p>\"Kami berkomitmen untuk mendukung generasi muda Indonesia yang berbakat di bidang teknik,\" ungkap Ketua Divisi Beasiswa PII.</p>', 'https://images.unsplash.com/photo-1427504494785-3a9ca7044f45?w=800&q=80', '2026-04-27 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'artikel_teknik', 'Pendidikan');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('28', 'Perubahan Regulasi Sertifikat Kompetensi Insinyur 2024', 'Divisi Regulasi', 'Pemerintah mengeluarkan regulasi baru terkait sertifikat kompetensi insinyur yang berlaku mulai tahun 2024.', '<p>Pemerintah melalui Kementerian PUPR mengeluarkan regulasi baru terkait sertifikat kompetensi insinyur yang berlaku mulai tahun 2024. Regulasi ini membawa beberapa perubahan signifikan dalam proses sertifikasi.</p><p>Beberapa poin penting dalam regulasi baru meliputi: penambahan kompetensi digital, peningkatan standar keselamatan, dan adopsi standar internasional.</p><p>PII menyambut baik regulasi ini dan berkomitmen untuk membantu anggota dalam proses transisi menuju sistem yang baru.</p>', 'https://images.unsplash.com/photo-1450101499163-c8848c66ca85?w=800&q=80', '2026-05-03 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regulasi', 'Regulasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('29', 'Inovasi AI dalam Perencanaan Proyek Konstruksi', 'Divisi Teknologi', 'Pemanfaatan kecerdasan buatan (AI) semakin merambah ke dunia konstruksi, membawa efisiensi yang signifikan.', '<p>Pemanfaatan kecerdasan buatan (AI) semakin merambah ke dunia konstruksi, membawa efisiensi yang signifikan dalam perencanaan dan pelaksanaan proyek.</p><p>Beberapa perusahaan konstruksi besar di Indonesia telah mulai mengadopsi teknologi AI untuk optimasi jadwal, prediksi risiko, dan manajemen sumber daya.</p><p>\"AI bukan pengganti insinyur, tapi alat bantu yang sangat powerful untuk meningkatkan akurasi dan efisiensi,\" jelas pakar konstruksi yang menjadi narasumber.</p>', 'https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=800&q=80', '2026-05-08 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Teknologi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('30', 'Masa Depan Profesi Insinyur di Era Digital', 'Prof. Dr. Ahmad Santoso', 'Refleksi tentang bagaimana profesi keinsinyuran harus beradaptasi dengan perkembangan teknologi digital.', '<p>Profesi keinsinyuran sedang menghadapi titik balik yang penting. Era digital tidak hanya mengubah cara kita bekerja, tapi juga mengubah esensi dari apa yang menjadi tanggung jawab seorang insinyur.</p><p>Di masa depan, insinyur tidak hanya dituntut untuk memahami fisika dan matematika, tapi juga harus menguasai data science, pemrograman, dan berbagai soft skills baru.</p><p>Adaptasi adalah kunci. Insinyur yang mampu menggabungkan pengetahuan teknik klasik dengan keterampilan digital akan menjadi pemimpin di era baru ini.</p>', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&q=80', '2026-05-07 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'opini', 'Opini');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('31', 'Peran Insinyur dalam Pembangunan Berkelanjutan', 'Dr. Rina Wijaya', 'Tanggung jawab insinyur tidak hanya menciptakan struktur yang kuat, tapi juga yang berkelanjutan bagi generasi mendatang.', '<p>Ketika kita berbicara tentang pembangunan berkelanjutan, peran insinyur menjadi sangat sentral. Setiap keputusan desain yang kita buat hari ini akan berdampak puluhan tahun ke depan.</p><p>Insinyur harus mulai memikirkan siklus hidup penuh dari setiap proyek, bukan hanya aspek konstruksi. Ini berarti mempertimbangkan dampak lingkungan, efisiensi energi, dan kemudahan perawatan.</p><p>Komitmen terhadap sustainability bukan lagi pilihan, tapi keharusan bagi profesi kita.</p>', 'https://images.unsplash.com/photo-1518173946687-a4c036bc3c95?w=800&q=80', '2026-05-05 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'opini', 'Opini');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('32', 'Teknik Sipil dan Tantangan Perubahan Iklim', 'Ir. Budi Hartono, M.Eng', 'Perubahan iklim membawa tantangan baru bagi insinyur sipil dalam merancang infrastruktur yang tangguh.', '<p>Perubahan iklim bukan lagi isu abstrak. Bagi insinyur sipil, ini adalah realitas yang harus dihadapi setiap hari dalam bentuk cuaca ekstrem, kenaikan muka air laut, dan perubahan pola curah hujan.</p><p>Infrastruktur yang kita bangun 20 tahun lalu mungkin tidak cukup kuat menghadapi kondisi iklim saat ini. Ini berarti kita perlu merevisi banyak standar dan spesifikasi teknis.</p><p>Resilience menjadi kata kunci dalam setiap proyek konstruksi modern. Bangunan tidak hanya harus kuat, tapi juga adaptif terhadap perubahan lingkungan.</p>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2026-05-02 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'artikel_teknik', 'Teknik Sipil');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('33', 'Transformasi Digital dalam Industri Manufaktur', 'Dr. Hendra Kusuma', 'Industri manufaktur Indonesia bertransformasi menuju Industry 4.0 dengan adopsi teknologi digital.', '<p>Transformasi digital dalam industri manufaktur bukan lagi tren, tapi kebutuhan untuk bertahan di pasar global. Perusahaan manufaktur Indonesia mulai mengadopsi teknologi IoT, AI, dan otomatisasi.</p><p>Insinyur manufaktur memiliki peran krusial dalam memimpin transformasi ini. Mereka harus memahami tidak hanya proses produksi konvensional, tapi juga integrasi sistem digital.</p><p>\"Indonesia memiliki potensi besar menjadi hub manufaktur digital di Asia Tenggara jika kita mampu mengoptimalkan SDM insinyur kita,\" ungkap pakar industri.</p>', 'https://images.unsplash.com/photo-1581092918056-0c4c3acd3789?w=800&q=80', '2026-04-30 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Industri 4.0');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('34', 'Pentingnya Keselamatan Kerja di Proyek Konstruksi', 'Divisi K3 PII', 'Keselamatan kerja adalah prioritas utama dalam setiap proyek konstruksi untuk melindungi pekerja dan masyarakat.', '<p>Kecelakaan kerja di sektor konstruksi masih menjadi isu serius di Indonesia. Data menunjukkan bahwa insiden kecelakaan bisa diminimalkan dengan penerapan standar K3 yang ketat.</p><p>PII terus mendorong penerapan standar keselamatan kerja internasional dalam setiap proyek konstruksi di Indonesia. Insinyur sebagai pemimpin proyek harus menjadi role model dalam penerapan K3.</p><p>\"Tidak ada proyek yang sepadan dengan nyawa manusia. K3 bukan biaya, tapi investasi,\" tegas Ketua Divisi K3 PII.</p>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2026-04-29 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regulasi', 'K3');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('35', 'Peluang Karir Insinyur di Sektor Energi Terbarukan', 'Ir. Diana Pratiwi', 'Sektor energi terbarukan menawarkan peluang karir yang menjanjikan bagi insinyur Indonesia.', '<p>Transisi energi global membuka peluang besar bagi insinyur Indonesia. Sektor energi terbarukan seperti surya, angin, dan panas bumi membutuhkan banyak tenaga ahli.</p><p>Indonesia memiliki potensi energi terbarukan yang sangat besar namun belum teroptimasi. Ini adalah kesempatan emas bagi insinyur untuk berkontribusi dalam mewujudkan energi bersih nasional.</p><p>\"Insinyur yang memiliki kompetensi di bidang EBT akan sangat dicari dalam 10 tahun ke depan,\" prediksi pakar energi.</p>', 'https://images.unsplash.com/photo-1509391366360-2e959784a276?w=800&q=80', '2026-04-28 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'opini', 'Karir');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('36', 'Smart City: Masa Depan Urban Planning Indonesia', 'Dr. Andi Wijaya', 'Konsep smart city mulai diterapkan di berbagai kota Indonesia dengan integrasi teknologi digital.', '<p>Lebih dari 100 kota di Indonesia sedang dalam proses transformasi menuju smart city. Konsep ini mengintegrasikan teknologi IoT, big data, dan AI dalam manajemen kota.</p><p>Insinyur memiliki peran penting dalam merancang infrastruktur digital yang mendukung smart city. Mulai dari sensor networks hingga sistem manajemen lalu lintas cerdas.</p><p>\"Smart city bukan hanya tentang teknologi, tapi tentang bagaimana teknologi meningkatkan kualitas hidup warga,\" jelas pakar urban planning.</p>', 'https://images.unsplash.com/photo-1573164713988-8665fc963095?w=800&q=80', '2026-04-26 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Smart City');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('37', 'Tantangan Insinyur dalam Pembangunan IKN', 'Tim IKN PII', 'Pembangunan Ibu Kota Nusantara membutuhkan peran insinyur Indonesia untuk menciptakan kota masa depan.', '<p>Pembangunan Ibu Kota Nusantara (IKN) adalah proyek strategis nasional yang membutuhkan kontribusi insinyur dari berbagai disiplin ilmu.</p><p>Tantangan yang dihadapi meliputi pembangunan infrastruktur yang tangguh, sistem transportasi terintegrasi, dan pengelolaan lingkungan yang berkelanjutan.</p><p>\"IKN adalah laboratorium besar bagi insinyur Indonesia untuk menunjukkan kemampuan kita di kancah internasional,\" ujar Ketua Tim IKN PII.</p>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2026-04-25 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'artikel_teknik', 'Infrastruktur');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('38', 'Sertifikasi Profesi Insinyur: Standar Baru 2024', 'Badan Sertifikasi PII', 'PII memperbarui standar sertifikasi profesi insinyur sesuai dengan perkembangan teknologi dan kebutuhan industri.', '<p>Standar sertifikasi profesi insinyur diperbarui untuk mengakomodasi kompetensi digital dan soft skills yang dibutuhkan di era modern.</p><p>Perubahan ini mencakup penambahan modul digital literacy, leadership, dan manajemen inovasi dalam kurikulum sertifikasi.</p><p>\"Tujuannya adalah memastikan insinyur Indonesia tidak hanya kompeten secara teknis, tapi juga siap menghadapi tantangan abad 21,\" jelas Ketua Badan Sertifikasi.</p>', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&q=80', '2026-04-24 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regulasi', 'Sertifikasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('39', 'Inovasi Material Konstruksi Ramah Lingkungan', 'Dr. Sari Lestari', 'Penelitian material konstruksi ramah lingkungan menawarkan alternatif sustainable untuk pembangunan.', '<p>Penelitian material konstruksi ramah lingkungan terus berkembang di Indonesia. Material seperti geopolymer concrete, bambu rekayasa, dan material daur ulang mulai banyak digunakan.</p><p>Insinyur material memiliki peran penting dalam mengembangkan dan menguji material-material baru ini untuk memastikan keamanan dan kualitasnya.</p><p>\"Material hijau bukan hanya tentang lingkungan, tapi juga tentang efisiensi biaya jangka panjang,\" ungkap peneliti material.</p>', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', '2026-04-23 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Material');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('40', 'Peran Insinyur dalam Mitigasi Bencana Alam', 'Divisi Bencana Alam PII', 'Insinyur memiliki peran krusial dalam merancang infrastruktur yang tahan bencana dan sistem peringatan dini.', '<p>Indonesia berada di zona rawan bencana seperti gempa, tsunami, dan banjir. Insinyur harus merancang infrastruktur yang tangguh terhadap ancaman ini.</p><p>Sistem peringatan dini, desain struktur tahan gempa, dan pengelolaan drainase adalah beberapa area di mana insinyur berkontribusi dalam mitigasi bencana.</p><p>\"Setiap insinyur harus memahami risiko bencana di area proyeknya dan merancang solusi yang sesuai,\" tegas ahli mitigasi bencana.</p>', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&q=80', '2026-04-22 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'artikel_teknik', 'Mitigasi Bencana');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('41', 'Mentoring untuk Insinyur Muda: Program Baru PII', 'Divisi Pengembangan Karir', 'PII meluncurkan program mentoring untuk menghubungkan insinyur muda dengan senior berpengalaman.', '<p>Program mentoring baru dari PII bertujuan menghubungkan insinyur muda dengan senior yang telah berpengalaman di bidangnya.</p><p>Setiap mentee akan dipasangkan dengan mentor yang sesuai dengan minat dan bidang keahliannya. Program ini berlangsung selama 6 bulan dengan sesi rutin.</p><p>\"Mentoring adalah cara terbaik untuk mentransfer pengetahuan dan pengalaman antar generasi insinyur,\" jelas koordinator program.</p>', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=800&q=80', '2026-04-21 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'opini', 'Pengembangan Karir');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('42', 'Digital Twins dalam Manajemen Aset Infrastruktur', 'Dr. Bambang Sutrisno', 'Teknologi digital twins mulai digunakan untuk manajemen aset infrastruktur yang lebih efektif.', '<p>Digital twins adalah replika digital dari aset fisik yang memungkinkan monitoring dan simulasi secara real-time. Teknologi ini mulai diadopsi di Indonesia.</p><p>Insinyur dapat menggunakan digital twins untuk memprediksi kebutuhan maintenance, optimasi operasional, dan perencanaan upgrade aset.</p><p>\"Digital twins mengubah cara kita mengelola infrastruktur dari reaktif menjadi prediktif,\" ungkap pakar teknologi.</p>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', '2026-04-20 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Teknologi Digital');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('43', 'Standar Internasional dalam Proyek Konstruksi Indonesia', 'Divisi Standar Teknis', 'Adopsi standar internasional meningkatkan kualitas dan daya saing proyek konstruksi Indonesia.', '<p>Proyek konstruksi Indonesia semakin banyak mengadopsi standar internasional seperti ISO, ASTM, dan standar Eropa.</p><p>Penerapan standar internasional meningkatkan kualitas konstruksi dan memudahkan kolaborasi dengan perusahaan asing.</p><p>\"Standar internasional bukan tentang mengikuti negara lain, tapi tentang memastikan kualitas yang setara,\" jelas ahli standar teknis.</p>', 'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=800&q=80', '2026-04-19 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regulasi', 'Standar');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('44', 'Peluang Riset untuk Insinyur Akademik', 'Prof. Dr. Yuliati', 'Insinyur akademik memiliki peluang besar untuk berkontribusi melalui riset dan publikasi ilmiah.', '<p>Insinyur yang berkarir di akademik memiliki peran ganda: mendidik generasi muda dan melakukan riset yang bermanfaat bagi industri.</p><p>Hibah riset dari pemerintah dan kolaborasi internasional semakin terbuka bagi peneliti Indonesia. Ini adalah kesempatan untuk meningkatkan kontribusi ilmiah.</p><p>\"Riset insinyur harus relevan dengan kebutuhan industri dan masyarakat,\" tegas profesor riset.</p>', 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=800&q=80', '2026-04-18 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'opini', 'Akademik');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('45', 'Automasi dalam Proyek Konstruksi Modern', 'Ir. Rudi Hartono', 'Teknologi automasi mulai diterapkan di berbagai aspek proyek konstruksi untuk meningkatkan efisiensi.', '<p>Dari robotik untuk pekerjaan berbahaya hingga drone untuk survey, automasi mengubah cara proyek konstruksi dieksekusi.</p><p>Insinyur harus memahami teknologi automasi untuk dapat mengintegrasikannya dalam perencanaan dan pelaksanaan proyek.</p><p>\"Automasi bukan menggantikan pekerja, tapi membuat pekerjaan lebih aman dan efisien,\" jelas praktisi konstruksi.</p>', 'https://images.unsplash.com/photo-1581092921461-eab62e97a780?w=800&q=80', '2026-04-17 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Automasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('46', 'Etika Profesi dalam Era Digital', 'Divisi Etika Profesi', 'Tantangan etika baru muncul seiring dengan digitalisasi profesi keinsinyuran.', '<p>Era digital membawa tantangan etika baru bagi insinyur: privasi data, keamanan siber, dan transparansi algoritma.</p><p>PII terus memperbarui kode etik profesi untuk mengakomodasi isu-isu digital ini dan memberikan panduan bagi anggota.</p><p>\"Etika bukan hanya tentang perilaku, tapi tentang tanggung jawab terhadap masyarakat,\" ungkap Ketua Divisi Etika.</p>', 'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=800&q=80', '2026-04-16 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regulasi', 'Etika');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('47', 'Kolaborasi Internasional untuk Proyek Infrastruktur', 'Divisi Luar Negeri', 'Insinyur Indonesia semakin terlibat dalam proyek infrastruktur internasional.', '<p>Insinyur Indonesia mulai mendapatkan pengakuan di kancah internasional dengan keterlibatan dalam proyek di berbagai negara.</p><p>Kolaborasi ini membawa pengalaman berharga dan membuka peluang untuk ekspor jasa teknik Indonesia.</p><p>\"Kualitas insinyur Indonesia tidak kalah dengan negara lain. Kita hanya perlu lebih percaya diri,\" ujar praktisi internasional.</p>', 'https://images.unsplash.com/photo-1578496479531-32e296d5c6e1?w=800&q=80', '2026-04-15 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'artikel_teknik', 'Kerjasama Internasional');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('48', 'Green Building Certification di Indonesia', 'Dr. Citra Dewi', 'Sertifikasi green building semakin populer sebagai standar bangunan ramah lingkungan.', '<p>Sertifikasi green building seperti GREENSHIP dan EDGE semakin banyak dicari oleh pengembang properti di Indonesia.</p><p>Insinyur memiliki peran penting dalam merancang bangunan yang memenuhi standar green building dari efisiensi energi hingga pengelolaan air.</p><p>\"Green building bukan tren, tapi kebutuhan untuk masa depan yang berkelanjutan,\" jelas ahli green building.</p>', 'https://images.unsplash.com/photo-1474487548417-781cb71495f3?w=800&q=80', '2026-04-14 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Sustainability');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('49', 'Entrepreneurship untuk Insinyur: Menjadi Founder', 'Ir. Denny Prasetyo', 'Banyak insinyur sukses menjadi founder startup teknologi dan perusahaan teknik.', '<p>Latar belakang teknik memberikan keunggulan bagi insinyur yang ingin menjadi entrepreneur. Kemampuan problem-solving dan pemahaman teknis adalah aset berharga.</p><p>PII mendukung anggota yang ingin berwirausaha melalui program inkubasi dan mentoring khusus.</p><p>\"Insinyur adalah problem solver alami. Ini adalah kualitas yang dibutuhkan entrepreneur,\" ungkap founder startup teknik.</p>', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&q=80', '2026-04-13 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'opini', 'Entrepreneurship');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('50', 'Manajemen Risiko dalam Proyek Besar', 'Divisi Manajemen Proyek', 'Manajemen risiko adalah kunci keberhasilan proyek konstruksi skala besar.', '<p>Proyek besar memiliki risiko yang kompleks mulai dari finansial hingga teknis. Manajemen risiko yang sistematis sangat penting.</p><p>Insinyur proyek harus memiliki kompetensi dalam identifikasi, analisis, dan mitigasi risiko sejak tahap perencanaan.</p><p>\"Proyek yang sukses bukan yang tidak memiliki risiko, tapi yang mampu mengelola risiko dengan baik,\" tegas ahli manajemen proyek.</p>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2026-04-12 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regulasi', 'Manajemen Proyek');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('51', 'Peran Insinyur dalam Pengembangan Transportasi Publik', 'Dr. Eko Prasetyo', 'Pengembangan transportasi publik membutuhkan integrasi berbagai disiplin teknik.', '<p>Transportasi publik modern seperti MRT, LRT, dan BRT membutuhkan integrasi teknik sipil, elektrikal, mekanikal, dan sistem.</p><p>Insinyur harus bekerja lintas disiplin untuk menciptakan sistem transportasi yang efisien, aman, dan nyaman bagi pengguna.</p><p>\"Transportasi publik adalah tentang integrasi sistem, bukan hanya membangun infrastruktur,\" jelas pakar transportasi.</p>', 'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=800&q=80', '2026-04-11 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'artikel_teknik', 'Transportasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('52', 'AI dalam Quality Control Konstruksi', 'Dr. Fitri Handayani', 'Kecerdasan buatan membantu meningkatkan akurasi quality control dalam proyek konstruksi.', '<p>AI dan computer vision digunakan untuk mendeteksi cacat konstruksi secara otomatis dan lebih akurat daripada inspeksi manual.</p><p>Teknologi ini mengurangi human error dan meningkatkan konsistensi dalam quality control proyek konstruksi.</p><p>\"AI tidak menggantikan insinyur QC, tapi meningkatkan kemampuan mereka mendeteksi masalah,\" ungkap peneliti AI.</p>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', '2026-04-10 13:40:33', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'inovasi', 'Teknologi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('53', 'PII Gelar Kongres Nasional Ke-32 di Jakarta', 'Humas PII', 'Persatuan Insinyur Indonesia sukses menyelenggarakan Kongres Nasional ke-32 yang dihadiri oleh lebih dari 500 insinyur dari seluruh Indonesia.', '<p>Persatuan Insinyur Indonesia sukses menyelenggarakan Kongres Nasional ke-32 yang dihadiri oleh lebih dari 500 insinyur dari seluruh Indonesia. Acara ini membahas berbagai isu strategis terkait pembangunan nasional dan peran insinyur dalam era digital.</p><p>Kongres yang berlangsung selama tiga hari ini menghasilkan beberapa rekomendasi penting untuk pengembangan profesi keinsinyuran di Indonesia. Para peserta aktif berdiskusi tentang tantangan dan peluang yang dihadapi oleh insinyur Indonesia di era globalisasi.</p><p>\"Kita harus memastikan bahwa insinyur Indonesia siap menghadapi revolusi industri 4.0. Ini bukan lagi tentang pilihan, tapi keharusan,\" ujar Ketua Umum PII dalam sambutannya.</p>', 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800&q=80', '2026-05-09 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'artikel_teknik', 'Kegiatan Nasional');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('54', 'Peluncuran Program Sertifikasi Baru untuk Insinyur Muda', 'Divisi Pendidikan', 'PII meluncurkan program sertifikasi baru yang dirancang khusus untuk insinyur muda untuk meningkatkan daya saing di pasar kerja.', '<p>PII meluncurkan program sertifikasi baru yang dirancang khusus untuk insinyur muda untuk meningkatkan daya saing di pasar kerja. Program ini mencakup berbagai kompetensi teknis dan soft skills yang dibutuhkan di industri 4.0.</p><p>Program sertifikasi ini terdiri dari beberapa level, mulai dari junior engineer hingga professional engineer. Setiap level memiliki kriteria dan standar kompetensi yang harus dipenuhi oleh peserta.</p><p>\"Dengan adanya program ini, kami berharap dapat meningkatkan kualitas insinyur Indonesia secara menyeluruh,\" jelas Direktur Pendidikan PII.</p>', 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?w=800&q=80', '2026-05-06 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'regulasi', 'Sertifikasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('55', 'Kerjasama PII dengan Berbagai Universitas', 'Kerjasama Luar Negeri', 'PII menjalin kerjasama strategis dengan universitas-universitas terkemuka untuk pengembangan pendidikan keinsinyuran.', '<p>PII menjalin kerjasama strategis dengan universitas-universitas terkemuka untuk pengembangan pendidikan keinsinyuran. Kerjasama ini meliputi pertukaran mahasiswa, joint research, dan program magang.</p><p>Beberapa universitas yang telah menjalin kerjasama meliputi ITB, UI, UGM, dan ITS. Kerjasama ini diharapkan dapat menjembatani dunia akademik dengan dunia industri.</p><p>\"Kolaborasi antara perguruan tinggi dan organisasi profesi sangat penting untuk memastikan lulusan siap kerja,\" ujar salah satu dekan teknik yang hadir dalam penandatanganan MoU.</p>', 'https://images.unsplash.com/photo-1562774053-701939374585?w=800&q=80', '2026-05-04 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Kerjasama');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('56', 'Seminar Nasional Teknologi Hijau 2024', 'Panitia Seminar', 'Seminar nasional yang membahas inovasi teknologi hijau untuk mendukung pembangunan berkelanjutan di Indonesia.', '<p>Seminar nasional yang membahas inovasi teknologi hijau untuk mendukung pembangunan berkelanjutan di Indonesia. Hadirkan pembicara ahli dari dalam dan luar negeri.</p><p>Teknologi hijau menjadi fokus utama dalam seminar ini, mengingat komitmen Indonesia untuk mengurangi emisi karbon. Berbagai solusi inovatif dari insinyur Indonesia dipresentasikan dalam acara ini.</p><p>\"Insinyur memiliki peran penting dalam menciptakan solusi teknologi yang ramah lingkungan,\" tegas salah satu pembicara kunci.</p>', 'https://images.unsplash.com/photo-1497436072909-60f360e1d4b1?w=800&q=80', '2026-05-01 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Teknologi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('57', 'Beasiswa PII untuk Mahasiswa Teknik', 'Divisi Beasiswa', 'PII membuka program beasiswa untuk mahasiswa teknik berprestasi dari seluruh Indonesia untuk tahun akademik 2024/2025.', '<p>PII membuka program beasiswa untuk mahasiswa teknik berprestasi dari seluruh Indonesia untuk tahun akademik 2024/2025. Beasiswa ini mencakup biaya pendidikan dan dukungan pengembangan karir.</p><p>Program beasiswa ini terbuka untuk mahasiswa semester 3-7 dari berbagai disiplin teknik. Seleksi dilakukan berdasarkan prestasi akademik, aktivitas organisasi, dan wawancara.</p><p>\"Kami berkomitmen untuk mendukung generasi muda Indonesia yang berbakat di bidang teknik,\" ungkap Ketua Divisi Beasiswa PII.</p>', 'https://images.unsplash.com/photo-1427504494785-3a9ca7044f45?w=800&q=80', '2026-04-27 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'artikel_teknik', 'Pendidikan');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('58', 'Perubahan Regulasi Sertifikat Kompetensi Insinyur 2024', 'Divisi Regulasi', 'Pemerintah mengeluarkan regulasi baru terkait sertifikat kompetensi insinyur yang berlaku mulai tahun 2024.', '<p>Pemerintah melalui Kementerian PUPR mengeluarkan regulasi baru terkait sertifikat kompetensi insinyur yang berlaku mulai tahun 2024. Regulasi ini membawa beberapa perubahan signifikan dalam proses sertifikasi.</p><p>Beberapa poin penting dalam regulasi baru meliputi: penambahan kompetensi digital, peningkatan standar keselamatan, dan adopsi standar internasional.</p><p>PII menyambut baik regulasi ini dan berkomitmen untuk membantu anggota dalam proses transisi menuju sistem yang baru.</p>', 'https://images.unsplash.com/photo-1450101499163-c8848c66ca85?w=800&q=80', '2026-05-03 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'regulasi', 'Regulasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('59', 'Inovasi AI dalam Perencanaan Proyek Konstruksi', 'Divisi Teknologi', 'Pemanfaatan kecerdasan buatan (AI) semakin merambah ke dunia konstruksi, membawa efisiensi yang signifikan.', '<p>Pemanfaatan kecerdasan buatan (AI) semakin merambah ke dunia konstruksi, membawa efisiensi yang signifikan dalam perencanaan dan pelaksanaan proyek.</p><p>Beberapa perusahaan konstruksi besar di Indonesia telah mulai mengadopsi teknologi AI untuk optimasi jadwal, prediksi risiko, dan manajemen sumber daya.</p><p>\"AI bukan pengganti insinyur, tapi alat bantu yang sangat powerful untuk meningkatkan akurasi dan efisiensi,\" jelas pakar konstruksi yang menjadi narasumber.</p>', 'https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=800&q=80', '2026-05-08 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Teknologi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('60', 'Masa Depan Profesi Insinyur di Era Digital', 'Prof. Dr. Ahmad Santoso', 'Refleksi tentang bagaimana profesi keinsinyuran harus beradaptasi dengan perkembangan teknologi digital.', '<p>Profesi keinsinyuran sedang menghadapi titik balik yang penting. Era digital tidak hanya mengubah cara kita bekerja, tapi juga mengubah esensi dari apa yang menjadi tanggung jawab seorang insinyur.</p><p>Di masa depan, insinyur tidak hanya dituntut untuk memahami fisika dan matematika, tapi juga harus menguasai data science, pemrograman, dan berbagai soft skills baru.</p><p>Adaptasi adalah kunci. Insinyur yang mampu menggabungkan pengetahuan teknik klasik dengan keterampilan digital akan menjadi pemimpin di era baru ini.</p>', 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=800&q=80', '2026-05-07 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'opini', 'Opini');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('61', 'Peran Insinyur dalam Pembangunan Berkelanjutan', 'Dr. Rina Wijaya', 'Tanggung jawab insinyur tidak hanya menciptakan struktur yang kuat, tapi juga yang berkelanjutan bagi generasi mendatang.', '<p>Ketika kita berbicara tentang pembangunan berkelanjutan, peran insinyur menjadi sangat sentral. Setiap keputusan desain yang kita buat hari ini akan berdampak puluhan tahun ke depan.</p><p>Insinyur harus mulai memikirkan siklus hidup penuh dari setiap proyek, bukan hanya aspek konstruksi. Ini berarti mempertimbangkan dampak lingkungan, efisiensi energi, dan kemudahan perawatan.</p><p>Komitmen terhadap sustainability bukan lagi pilihan, tapi keharusan bagi profesi kita.</p>', 'https://images.unsplash.com/photo-1518173946687-a4c036bc3c95?w=800&q=80', '2026-05-05 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'opini', 'Opini');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('62', 'Teknik Sipil dan Tantangan Perubahan Iklim', 'Ir. Budi Hartono, M.Eng', 'Perubahan iklim membawa tantangan baru bagi insinyur sipil dalam merancang infrastruktur yang tangguh.', '<p>Perubahan iklim bukan lagi isu abstrak. Bagi insinyur sipil, ini adalah realitas yang harus dihadapi setiap hari dalam bentuk cuaca ekstrem, kenaikan muka air laut, dan perubahan pola curah hujan.</p><p>Infrastruktur yang kita bangun 20 tahun lalu mungkin tidak cukup kuat menghadapi kondisi iklim saat ini. Ini berarti kita perlu merevisi banyak standar dan spesifikasi teknis.</p><p>Resilience menjadi kata kunci dalam setiap proyek konstruksi modern. Bangunan tidak hanya harus kuat, tapi juga adaptif terhadap perubahan lingkungan.</p>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2026-05-02 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'artikel_teknik', 'Teknik Sipil');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('63', 'Transformasi Digital dalam Industri Manufaktur', 'Dr. Hendra Kusuma', 'Industri manufaktur Indonesia bertransformasi menuju Industry 4.0 dengan adopsi teknologi digital.', '<p>Transformasi digital dalam industri manufaktur bukan lagi tren, tapi kebutuhan untuk bertahan di pasar global. Perusahaan manufaktur Indonesia mulai mengadopsi teknologi IoT, AI, dan otomatisasi.</p><p>Insinyur manufaktur memiliki peran krusial dalam memimpin transformasi ini. Mereka harus memahami tidak hanya proses produksi konvensional, tapi juga integrasi sistem digital.</p><p>\"Indonesia memiliki potensi besar menjadi hub manufaktur digital di Asia Tenggara jika kita mampu mengoptimalkan SDM insinyur kita,\" ungkap pakar industri.</p>', 'https://images.unsplash.com/photo-1581092918056-0c4c3acd3789?w=800&q=80', '2026-04-30 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Industri 4.0');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('64', 'Pentingnya Keselamatan Kerja di Proyek Konstruksi', 'Divisi K3 PII', 'Keselamatan kerja adalah prioritas utama dalam setiap proyek konstruksi untuk melindungi pekerja dan masyarakat.', '<p>Kecelakaan kerja di sektor konstruksi masih menjadi isu serius di Indonesia. Data menunjukkan bahwa insiden kecelakaan bisa diminimalkan dengan penerapan standar K3 yang ketat.</p><p>PII terus mendorong penerapan standar keselamatan kerja internasional dalam setiap proyek konstruksi di Indonesia. Insinyur sebagai pemimpin proyek harus menjadi role model dalam penerapan K3.</p><p>\"Tidak ada proyek yang sepadan dengan nyawa manusia. K3 bukan biaya, tapi investasi,\" tegas Ketua Divisi K3 PII.</p>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2026-04-29 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'regulasi', 'K3');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('65', 'Peluang Karir Insinyur di Sektor Energi Terbarukan', 'Ir. Diana Pratiwi', 'Sektor energi terbarukan menawarkan peluang karir yang menjanjikan bagi insinyur Indonesia.', '<p>Transisi energi global membuka peluang besar bagi insinyur Indonesia. Sektor energi terbarukan seperti surya, angin, dan panas bumi membutuhkan banyak tenaga ahli.</p><p>Indonesia memiliki potensi energi terbarukan yang sangat besar namun belum teroptimasi. Ini adalah kesempatan emas bagi insinyur untuk berkontribusi dalam mewujudkan energi bersih nasional.</p><p>\"Insinyur yang memiliki kompetensi di bidang EBT akan sangat dicari dalam 10 tahun ke depan,\" prediksi pakar energi.</p>', 'https://images.unsplash.com/photo-1509391366360-2e959784a276?w=800&q=80', '2026-04-28 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'opini', 'Karir');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('66', 'Smart City: Masa Depan Urban Planning Indonesia', 'Dr. Andi Wijaya', 'Konsep smart city mulai diterapkan di berbagai kota Indonesia dengan integrasi teknologi digital.', '<p>Lebih dari 100 kota di Indonesia sedang dalam proses transformasi menuju smart city. Konsep ini mengintegrasikan teknologi IoT, big data, dan AI dalam manajemen kota.</p><p>Insinyur memiliki peran penting dalam merancang infrastruktur digital yang mendukung smart city. Mulai dari sensor networks hingga sistem manajemen lalu lintas cerdas.</p><p>\"Smart city bukan hanya tentang teknologi, tapi tentang bagaimana teknologi meningkatkan kualitas hidup warga,\" jelas pakar urban planning.</p>', 'https://images.unsplash.com/photo-1573164713988-8665fc963095?w=800&q=80', '2026-04-26 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Smart City');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('67', 'Tantangan Insinyur dalam Pembangunan IKN', 'Tim IKN PII', 'Pembangunan Ibu Kota Nusantara membutuhkan peran insinyur Indonesia untuk menciptakan kota masa depan.', '<p>Pembangunan Ibu Kota Nusantara (IKN) adalah proyek strategis nasional yang membutuhkan kontribusi insinyur dari berbagai disiplin ilmu.</p><p>Tantangan yang dihadapi meliputi pembangunan infrastruktur yang tangguh, sistem transportasi terintegrasi, dan pengelolaan lingkungan yang berkelanjutan.</p><p>\"IKN adalah laboratorium besar bagi insinyur Indonesia untuk menunjukkan kemampuan kita di kancah internasional,\" ujar Ketua Tim IKN PII.</p>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2026-04-25 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'artikel_teknik', 'Infrastruktur');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('68', 'Sertifikasi Profesi Insinyur: Standar Baru 2024', 'Badan Sertifikasi PII', 'PII memperbarui standar sertifikasi profesi insinyur sesuai dengan perkembangan teknologi dan kebutuhan industri.', '<p>Standar sertifikasi profesi insinyur diperbarui untuk mengakomodasi kompetensi digital dan soft skills yang dibutuhkan di era modern.</p><p>Perubahan ini mencakup penambahan modul digital literacy, leadership, dan manajemen inovasi dalam kurikulum sertifikasi.</p><p>\"Tujuannya adalah memastikan insinyur Indonesia tidak hanya kompeten secara teknis, tapi juga siap menghadapi tantangan abad 21,\" jelas Ketua Badan Sertifikasi.</p>', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&q=80', '2026-04-24 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'regulasi', 'Sertifikasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('69', 'Inovasi Material Konstruksi Ramah Lingkungan', 'Dr. Sari Lestari', 'Penelitian material konstruksi ramah lingkungan menawarkan alternatif sustainable untuk pembangunan.', '<p>Penelitian material konstruksi ramah lingkungan terus berkembang di Indonesia. Material seperti geopolymer concrete, bambu rekayasa, dan material daur ulang mulai banyak digunakan.</p><p>Insinyur material memiliki peran penting dalam mengembangkan dan menguji material-material baru ini untuk memastikan keamanan dan kualitasnya.</p><p>\"Material hijau bukan hanya tentang lingkungan, tapi juga tentang efisiensi biaya jangka panjang,\" ungkap peneliti material.</p>', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', '2026-04-23 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Material');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('70', 'Peran Insinyur dalam Mitigasi Bencana Alam', 'Divisi Bencana Alam PII', 'Insinyur memiliki peran krusial dalam merancang infrastruktur yang tahan bencana dan sistem peringatan dini.', '<p>Indonesia berada di zona rawan bencana seperti gempa, tsunami, dan banjir. Insinyur harus merancang infrastruktur yang tangguh terhadap ancaman ini.</p><p>Sistem peringatan dini, desain struktur tahan gempa, dan pengelolaan drainase adalah beberapa area di mana insinyur berkontribusi dalam mitigasi bencana.</p><p>\"Setiap insinyur harus memahami risiko bencana di area proyeknya dan merancang solusi yang sesuai,\" tegas ahli mitigasi bencana.</p>', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&q=80', '2026-04-22 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'artikel_teknik', 'Mitigasi Bencana');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('71', 'Mentoring untuk Insinyur Muda: Program Baru PII', 'Divisi Pengembangan Karir', 'PII meluncurkan program mentoring untuk menghubungkan insinyur muda dengan senior berpengalaman.', '<p>Program mentoring baru dari PII bertujuan menghubungkan insinyur muda dengan senior yang telah berpengalaman di bidangnya.</p><p>Setiap mentee akan dipasangkan dengan mentor yang sesuai dengan minat dan bidang keahliannya. Program ini berlangsung selama 6 bulan dengan sesi rutin.</p><p>\"Mentoring adalah cara terbaik untuk mentransfer pengetahuan dan pengalaman antar generasi insinyur,\" jelas koordinator program.</p>', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=800&q=80', '2026-04-21 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'opini', 'Pengembangan Karir');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('72', 'Digital Twins dalam Manajemen Aset Infrastruktur', 'Dr. Bambang Sutrisno', 'Teknologi digital twins mulai digunakan untuk manajemen aset infrastruktur yang lebih efektif.', '<p>Digital twins adalah replika digital dari aset fisik yang memungkinkan monitoring dan simulasi secara real-time. Teknologi ini mulai diadopsi di Indonesia.</p><p>Insinyur dapat menggunakan digital twins untuk memprediksi kebutuhan maintenance, optimasi operasional, dan perencanaan upgrade aset.</p><p>\"Digital twins mengubah cara kita mengelola infrastruktur dari reaktif menjadi prediktif,\" ungkap pakar teknologi.</p>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', '2026-04-20 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Teknologi Digital');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('73', 'Standar Internasional dalam Proyek Konstruksi Indonesia', 'Divisi Standar Teknis', 'Adopsi standar internasional meningkatkan kualitas dan daya saing proyek konstruksi Indonesia.', '<p>Proyek konstruksi Indonesia semakin banyak mengadopsi standar internasional seperti ISO, ASTM, dan standar Eropa.</p><p>Penerapan standar internasional meningkatkan kualitas konstruksi dan memudahkan kolaborasi dengan perusahaan asing.</p><p>\"Standar internasional bukan tentang mengikuti negara lain, tapi tentang memastikan kualitas yang setara,\" jelas ahli standar teknis.</p>', 'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=800&q=80', '2026-04-19 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'regulasi', 'Standar');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('74', 'Peluang Riset untuk Insinyur Akademik', 'Prof. Dr. Yuliati', 'Insinyur akademik memiliki peluang besar untuk berkontribusi melalui riset dan publikasi ilmiah.', '<p>Insinyur yang berkarir di akademik memiliki peran ganda: mendidik generasi muda dan melakukan riset yang bermanfaat bagi industri.</p><p>Hibah riset dari pemerintah dan kolaborasi internasional semakin terbuka bagi peneliti Indonesia. Ini adalah kesempatan untuk meningkatkan kontribusi ilmiah.</p><p>\"Riset insinyur harus relevan dengan kebutuhan industri dan masyarakat,\" tegas profesor riset.</p>', 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=800&q=80', '2026-04-18 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'opini', 'Akademik');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('75', 'Automasi dalam Proyek Konstruksi Modern', 'Ir. Rudi Hartono', 'Teknologi automasi mulai diterapkan di berbagai aspek proyek konstruksi untuk meningkatkan efisiensi.', '<p>Dari robotik untuk pekerjaan berbahaya hingga drone untuk survey, automasi mengubah cara proyek konstruksi dieksekusi.</p><p>Insinyur harus memahami teknologi automasi untuk dapat mengintegrasikannya dalam perencanaan dan pelaksanaan proyek.</p><p>\"Automasi bukan menggantikan pekerja, tapi membuat pekerjaan lebih aman dan efisien,\" jelas praktisi konstruksi.</p>', 'https://images.unsplash.com/photo-1581092921461-eab62e97a780?w=800&q=80', '2026-04-17 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Automasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('76', 'Etika Profesi dalam Era Digital', 'Divisi Etika Profesi', 'Tantangan etika baru muncul seiring dengan digitalisasi profesi keinsinyuran.', '<p>Era digital membawa tantangan etika baru bagi insinyur: privasi data, keamanan siber, dan transparansi algoritma.</p><p>PII terus memperbarui kode etik profesi untuk mengakomodasi isu-isu digital ini dan memberikan panduan bagi anggota.</p><p>\"Etika bukan hanya tentang perilaku, tapi tentang tanggung jawab terhadap masyarakat,\" ungkap Ketua Divisi Etika.</p>', 'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=800&q=80', '2026-04-16 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'regulasi', 'Etika');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('77', 'Kolaborasi Internasional untuk Proyek Infrastruktur', 'Divisi Luar Negeri', 'Insinyur Indonesia semakin terlibat dalam proyek infrastruktur internasional.', '<p>Insinyur Indonesia mulai mendapatkan pengakuan di kancah internasional dengan keterlibatan dalam proyek di berbagai negara.</p><p>Kolaborasi ini membawa pengalaman berharga dan membuka peluang untuk ekspor jasa teknik Indonesia.</p><p>\"Kualitas insinyur Indonesia tidak kalah dengan negara lain. Kita hanya perlu lebih percaya diri,\" ujar praktisi internasional.</p>', 'https://images.unsplash.com/photo-1578496479531-32e296d5c6e1?w=800&q=80', '2026-04-15 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'artikel_teknik', 'Kerjasama Internasional');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('78', 'Green Building Certification di Indonesia', 'Dr. Citra Dewi', 'Sertifikasi green building semakin populer sebagai standar bangunan ramah lingkungan.', '<p>Sertifikasi green building seperti GREENSHIP dan EDGE semakin banyak dicari oleh pengembang properti di Indonesia.</p><p>Insinyur memiliki peran penting dalam merancang bangunan yang memenuhi standar green building dari efisiensi energi hingga pengelolaan air.</p><p>\"Green building bukan tren, tapi kebutuhan untuk masa depan yang berkelanjutan,\" jelas ahli green building.</p>', 'https://images.unsplash.com/photo-1474487548417-781cb71495f3?w=800&q=80', '2026-04-14 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Sustainability');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('79', 'Entrepreneurship untuk Insinyur: Menjadi Founder', 'Ir. Denny Prasetyo', 'Banyak insinyur sukses menjadi founder startup teknologi dan perusahaan teknik.', '<p>Latar belakang teknik memberikan keunggulan bagi insinyur yang ingin menjadi entrepreneur. Kemampuan problem-solving dan pemahaman teknis adalah aset berharga.</p><p>PII mendukung anggota yang ingin berwirausaha melalui program inkubasi dan mentoring khusus.</p><p>\"Insinyur adalah problem solver alami. Ini adalah kualitas yang dibutuhkan entrepreneur,\" ungkap founder startup teknik.</p>', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&q=80', '2026-04-13 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'opini', 'Entrepreneurship');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('80', 'Manajemen Risiko dalam Proyek Besar', 'Divisi Manajemen Proyek', 'Manajemen risiko adalah kunci keberhasilan proyek konstruksi skala besar.', '<p>Proyek besar memiliki risiko yang kompleks mulai dari finansial hingga teknis. Manajemen risiko yang sistematis sangat penting.</p><p>Insinyur proyek harus memiliki kompetensi dalam identifikasi, analisis, dan mitigasi risiko sejak tahap perencanaan.</p><p>\"Proyek yang sukses bukan yang tidak memiliki risiko, tapi yang mampu mengelola risiko dengan baik,\" tegas ahli manajemen proyek.</p>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2026-04-12 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'regulasi', 'Manajemen Proyek');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('81', 'Peran Insinyur dalam Pengembangan Transportasi Publik', 'Dr. Eko Prasetyo', 'Pengembangan transportasi publik membutuhkan integrasi berbagai disiplin teknik.', '<p>Transportasi publik modern seperti MRT, LRT, dan BRT membutuhkan integrasi teknik sipil, elektrikal, mekanikal, dan sistem.</p><p>Insinyur harus bekerja lintas disiplin untuk menciptakan sistem transportasi yang efisien, aman, dan nyaman bagi pengguna.</p><p>\"Transportasi publik adalah tentang integrasi sistem, bukan hanya membangun infrastruktur,\" jelas pakar transportasi.</p>', 'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=800&q=80', '2026-04-11 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'artikel_teknik', 'Transportasi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('82', 'AI dalam Quality Control Konstruksi', 'Dr. Fitri Handayani', 'Kecerdasan buatan membantu meningkatkan akurasi quality control dalam proyek konstruksi.', '<p>AI dan computer vision digunakan untuk mendeteksi cacat konstruksi secara otomatis dan lebih akurat daripada inspeksi manual.</p><p>Teknologi ini mengurangi human error dan meningkatkan konsistensi dalam quality control proyek konstruksi.</p><p>\"AI tidak menggantikan insinyur QC, tapi meningkatkan kemampuan mereka mendeteksi masalah,\" ungkap peneliti AI.</p>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', '2026-04-10 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'inovasi', 'Teknologi');
INSERT INTO `beritas` (`id`, `title`, `author`, `excerpt`, `content`, `image`, `published_at`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('83', 'Sertifikasi Profesi Insinyur Indonesia 2024', 'Divisi Sertifikasi PII', 'Program sertifikasi profesi insinyur kini mengadopsi standar internasional untuk meningkatkan kompetensi.', '<p>PII meluncurkan program sertifikasi profesi insinyur yang diselaraskan dengan standar internasional seperti Washington Accord dan Sydney Accord.</p><p>Program ini mencakup berbagai spesialisasi teknik: sipil, mesin, elektro, industri, dan lainnya. Sertifikasi ini diakui di berbagai negara.</p><p>\"Sertifikasi internasional membuka peluang karir global bagi insinyur Indonesia,\" jelas Direktur Sertifikasi PII.</p>', 'https://images.unsplash.com/photo-1450101499163-c8848c66ca85?w=800&q=80', '2026-04-09 14:28:26', '1', '2026-05-11 14:28:26', '2026-05-11 14:28:26', 'regulasi', 'Sertifikasi');

