DROP TABLE IF EXISTS `visi_misis`;
CREATE TABLE `visi_misis` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `content` text, `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);

INSERT INTO `visi_misis` (`id`, `title`, `content`, `is_active`, `created_at`, `updated_at`) VALUES ('1', 'Visi Misi PII', '<p class=\"leading-7 py-1\" dir=\"ltr\">Sebagai organisasi profesi yang memayungi para insinyur di Indonesia, Persatuan Insinyur Indonesia (PII) memiliki peran penting dalam meningkatkan kualitas dan profesionalisme insinyur, serta mendukung pembangunan nasional yang berkelanjutan. Untuk mencapai tujuan tersebut, PII menetapkan visi dan misi berikut:</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\"><strong class=\"font-bold\">Visi</strong></p>
<p class=\"leading-7 py-1\" dir=\"ltr\">Persatuan Insinyur Indonesia sebagai wadah strategis bagi Insinyur Nusantara untuk mewujudkan Indonesia Emas yang mandiri, maju, dan berkelanjutan melalui inovasi dan kolaborasi.</p>
<p class=\"leading-7 py-1\">&nbsp;</p>
<p class=\"leading-7 py-1\" dir=\"ltr\"><strong class=\"font-bold\">Misi</strong></p>
<ol>
<li>Mewujudkan Insinyur Nusantara yang Terbuka, Inovatif, dan Kolaboratif baik Nasional dan Internasional.</li>
<li>Menguatkan Literasi Digital sebagai Fondasi Transformasi Keinsinyuran.</li>
<li>Menerapkan Strategi Produk dan Jasa Industri Berbasis Teknologi Tepat Guna.</li>
<li>Menginisiasi dan Mengembangkan Proyek Percontohan di Berbagai Sektor dan Wilayah Indonesia.</li>
<li>Melakukan Transformasi Digital dalam Tata Kelola dan Manajemen Organisasi PII.</li>
</ol>', '1', '2026-05-11 12:33:24', '2026-05-11 12:39:35');

DROP TABLE IF EXISTS `events`;
CREATE TABLE `events` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255) not null, `type` VARCHAR(255) not null, `description` text, `content` text, `image` VARCHAR(255), `event_date` datetime, `location` VARCHAR(255), `link` VARCHAR(255), `is_active` tinyint(1) not null default ('1'), `created_at` datetime, `updated_at` datetime, `category` VARCHAR(255), `sub_category` VARCHAR(255));

INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('1', 'Seminar Nasional Keinsinyuran 2025', 'seminar', 'Seminar nasional membahas peran insinyur dalam pembangunan infrastruktur berkelanjutan di Indonesia.', '<p>Seminar Nasional Keinsinyuran 2025 akan menghadirkan para pakar dan praktisi terkemuka di bidang keinsinyuran untuk membahas isu-isu strategis dalam pembangunan infrastruktur Indonesia.</p><p><strong>Topik yang akan dibahas:</strong></p><ul><li>Infrastruktur hijau dan berkelanjutan</li><li>Digitalisasi dalam dunia konstruksi</li><li>Standar keselamatan bangunan terkini</li></ul>', NULL, '2025-08-15 09:00:00', 'Jakarta Convention Center, Jakarta', 'https://pii.or.id/seminar-nasional-2025', '1', '2026-05-11 12:49:13', '2026-05-11 12:49:13', 'nasional', 'Infrastruktur & Pembangunan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('2', 'Pelatihan BIM (Building Information Modeling) Level 1', 'pelatihan', 'Pelatihan intensif BIM untuk insinyur sipil dan arsitek yang ingin meningkatkan kompetensi digital mereka.', '<p>Pelatihan BIM Level 1 dirancang khusus untuk para profesional di bidang konstruksi yang ingin memahami dan mengimplementasikan Building Information Modeling dalam proyek mereka.</p><p><strong>Materi Pelatihan:</strong></p><ol><li>Pengenalan dan konsep dasar BIM</li><li>Software Revit untuk pemula</li><li>Kolaborasi tim berbasis BIM</li><li>Studi kasus proyek nyata</li></ol>', NULL, '2025-09-05 08:00:00', 'Gedung PII, Menteng, Jakarta Pusat', 'https://pii.or.id/pelatihan-bim-2025', '1', '2026-05-11 12:49:13', '2026-05-11 12:49:13', 'nasional', 'Teknologi Konstruksi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('3', 'Konvensi Insinyur Internasional Asia Pacific 2025', 'konferensi', 'Konvensi tahunan insinyur se-Asia Pacific membahas tantangan dan peluang di era revolusi industri 4.0.', '<p>Konvensi Insinyur Internasional Asia Pacific 2025 merupakan ajang bergengsi yang mempertemukan para insinyur dari seluruh kawasan Asia Pacific.</p><p>Tahun ini mengangkat tema <strong>\"Engineering for a Sustainable Future\"</strong> dengan fokus pada:</p><ul><li>Energi terbarukan dan transisi energi</li><li>Smart city dan infrastruktur digital</li><li>Ketahanan terhadap perubahan iklim</li><li>Kolaborasi riset antar negara</li></ul>', NULL, '2025-10-20 08:00:00', 'Bali International Convention Centre, Bali', 'https://pii.or.id/konvensi-internasional-2025', '1', '2026-05-11 12:49:13', '2026-05-11 12:49:13', 'internasional', 'Asia Pacific Engineering Forum');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('6', 'Pelatihan Sertifikasi Insinyur Profesional (IP)', 'pelatihan', 'Program persiapan sertifikasi Insinyur Profesional (IP) untuk anggota PII yang ingin meningkatkan jenjang karir.', '<p>Sertifikasi Insinyur Profesional (IP) adalah pengakuan resmi atas kompetensi seorang insinyur dalam bidangnya. Program pelatihan ini dirancang untuk mempersiapkan peserta menghadapi ujian sertifikasi IP.</p><p><strong>Modul Pelatihan:</strong></p><ol><li>Etika profesi keinsinyuran</li><li>Standar dan regulasi teknis</li><li>Manajemen proyek engineering</li><li>Simulasi soal ujian IP</li><li>Sesi tanya jawab dengan penguji bersertifikat</li></ol><p>Peserta yang lulus akan mendapatkan <strong>sertifikat keikutsertaan</strong> dan dapat langsung mendaftar ujian IP resmi PII.</p>', NULL, '2025-11-08 08:00:00', 'Graha PII, Jakarta Selatan', 'https://pii.or.id/sertifikasi-ip-2025', '1', '2026-05-11 12:49:13', '2026-05-11 12:49:13', 'nasional', 'Sertifikasi & Kompetensi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('8', 'Pelatihan BIM (Building Information Modeling) Level 1', 'pelatihan', 'Pelatihan intensif BIM untuk insinyur sipil dan arsitek yang ingin meningkatkan kompetensi digital mereka.', '<p>Pelatihan BIM Level 1 dirancang khusus untuk para profesional di bidang konstruksi yang ingin memahami dan mengimplementasikan Building Information Modeling dalam proyek mereka.</p><p><strong>Materi Pelatihan:</strong></p><ol><li>Pengenalan dan konsep dasar BIM</li><li>Software Revit untuk pemula</li><li>Kolaborasi tim berbasis BIM</li><li>Studi kasus proyek nyata</li></ol>', NULL, '2025-09-05 08:00:00', 'Gedung PII, Menteng, Jakarta Pusat', 'https://pii.or.id/pelatihan-bim-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Teknologi Konstruksi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('9', 'Konvensi Insinyur Internasional Asia Pacific 2025', 'konferensi', 'Konvensi tahunan insinyur se-Asia Pacific membahas tantangan dan peluang di era revolusi industri 4.0.', '<p>Konvensi Insinyur Internasional Asia Pacific 2025 merupakan ajang bergengsi yang mempertemukan para insinyur dari seluruh kawasan Asia Pacific.</p><p>Tahun ini mengangkat tema <strong>\"Engineering for a Sustainable Future\"</strong> dengan fokus pada:</p><ul><li>Energi terbarukan dan transisi energi</li><li>Smart city dan infrastruktur digital</li><li>Ketahanan terhadap perubahan iklim</li><li>Kolaborasi riset antar negara</li></ul>', NULL, '2025-10-20 08:00:00', 'Bali International Convention Centre, Bali', 'https://pii.or.id/konvensi-internasional-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'internasional', 'Asia Pacific Engineering Forum');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('12', 'Pelatihan Sertifikasi Insinyur Profesional (IP)', 'pelatihan', 'Program persiapan sertifikasi Insinyur Profesional (IP) untuk anggota PII yang ingin meningkatkan jenjang karir.', '<p>Sertifikasi Insinyur Profesional (IP) adalah pengakuan resmi atas kompetensi seorang insinyur dalam bidangnya. Program pelatihan ini dirancang untuk mempersiapkan peserta menghadapi ujian sertifikasi IP.</p><p><strong>Modul Pelatihan:</strong></p><ol><li>Etika profesi keinsinyuran</li><li>Standar dan regulasi teknis</li><li>Manajemen proyek engineering</li><li>Simulasi soal ujian IP</li><li>Sesi tanya jawab dengan penguji bersertifikat</li></ol><p>Peserta yang lulus akan mendapatkan <strong>sertifikat keikutsertaan</strong> dan dapat langsung mendaftar ujian IP resmi PII.</p>', NULL, '2025-11-08 08:00:00', 'Graha PII, Jakarta Selatan', 'https://pii.or.id/sertifikasi-ip-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Sertifikasi & Kompetensi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('13', 'Workshop Inovasi Infrastruktur Hijau', 'seminar', 'Workshop membahas pendekatan terbaru dalam pembangunan infrastruktur yang ramah lingkungan dan berkelanjutan.', '<p>Workshop ini menghadirkan para pakar infrastruktur hijau dari seluruh Indonesia untuk berbagi pengetahuan dan praktik terbaik dalam membangun infrastruktur yang berkelanjutan.</p><ul><li>Green building standards dan sertifikasi</li><li>Material konstruksi ramah lingkungan</li><li>Manajemen energi pada bangunan</li><li>Studi kasus proyek sukses</li></ul>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2025-07-22 08:00:00', 'Bandung Convention Centre, Bandung', 'https://pii.or.id/workshop-infrastruktur-hijau', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Infrastruktur Berkelanjutan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('14', 'Pelatihan Manajemen Proyek Konstruksi Level Lanjut', 'pelatihan', 'Pelatihan intensif 3 hari untuk meningkatkan kemampuan manajemen proyek konstruksi skala besar.', '<p>Program pelatihan lanjutan ini dirancang untuk insinyur berpengalaman yang ingin meningkatkan kompetensi dalam mengelola proyek konstruksi skala besar dan kompleks.</p><ol><li>Advanced scheduling dengan Primavera P6</li><li>Risk management dalam proyek konstruksi</li><li>Contract management dan klaim</li><li>Leadership dan team management</li></ol>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2025-08-12 08:00:00', 'Hotel Pullman, Jakarta Pusat', 'https://pii.or.id/pelatihan-pm-lanjut', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Project Management');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('15', 'Konvensi Tahunan Insinyur Sipil Indonesia 2025', 'konferensi', 'Konvensi tahunan untuk insinyur sipil membahas perkembangan terkini teknologi dan standar konstruksi.', '<p>Konvensi Tahunan Insinyur Sipil Indonesia 2025 adalah forum bergengsi yang mempertemukan ribuan insinyur sipil dari seluruh nusantara.</p><p>Tema tahun ini: <strong>\"Resilient Infrastructure for Indonesia 2045\"</strong></p><ul><li>Keynote dari Menteri PUPR</li><li>Panel diskusi pembangunan IKN</li><li>Pameran teknologi konstruksi terbaru</li><li>Networking session</li></ul>', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', '2025-09-18 08:00:00', 'Surabaya Convention Hall, Surabaya', 'https://pii.or.id/konvensi-sipil-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Teknik Sipil');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('16', 'Webinar: AI dan Machine Learning untuk Insinyur', 'seminar', 'Webinar gratis mengenai penerapan AI dan machine learning dalam berbagai bidang keinsinyuran.', '<p>Di era kecerdasan buatan, insinyur perlu memahami bagaimana AI dapat digunakan untuk meningkatkan efisiensi dan akurasi pekerjaan mereka.</p><p><strong>Yang akan dibahas:</strong></p><ul><li>Pengantar AI dan ML untuk non-programmer</li><li>Computer vision dalam inspeksi infrastruktur</li><li>Predictive maintenance dengan ML</li><li>Tools AI yang bisa langsung digunakan</li></ul>', 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=800&q=80', '2025-07-30 14:00:00', 'Google Meet (Online)', 'https://meet.google.com/pii-ai-webinar', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'online', 'Artificial Intelligence');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('17', 'Pelatihan AutoCAD & Revit untuk Insinyur Mekanikal', 'pelatihan', 'Pelatihan software desain AutoCAD dan Revit khusus untuk insinyur di bidang mekanikal dan elektrikal.', '<p>Kuasai dua software desain paling populer di industri konstruksi dan manufaktur. Pelatihan ini mencakup dasar hingga tingkat mahir dalam penggunaan AutoCAD dan Revit untuk aplikasi mekanikal.</p><ol><li>AutoCAD 2D fundamentals</li><li>AutoCAD 3D modelling</li><li>Revit MEP basics</li><li>Koordinasi antar disiplin dengan BIM</li></ol>', 'https://images.unsplash.com/photo-1581092918056-0c4c3acd3789?w=800&q=80', '2025-08-05 08:00:00', 'Pusat Pelatihan PII, Semarang', NULL, '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'regional', 'CAD & BIM');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('18', 'Forum Insinyur Muda Indonesia 2025', 'seminar', 'Forum tahunan khusus untuk insinyur muda berusia di bawah 35 tahun untuk berjejaring dan berbagi ide.', '<p>Forum Insinyur Muda Indonesia (FIMI) 2025 adalah ruang bagi generasi insinyur muda untuk saling terhubung, berbagi gagasan inovatif, dan merumuskan kontribusi nyata bagi kemajuan bangsa.</p><p><strong>Highlight acara:</strong></p><ul><li>Pitch kompetisi inovasi teknik</li><li>Mentoring dengan senior insinyur</li><li>Career development workshop</li><li>Networking dengan perusahaan top</li></ul>', 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800&q=80', '2025-10-04 08:00:00', 'Universitas Indonesia, Depok', 'https://pii.or.id/fimi-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Young Engineers');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('19', 'Pelatihan Teknik Geoteknik dan Pondasi', 'pelatihan', 'Pelatihan mendalam mengenai analisis tanah, desain pondasi, dan penanganan masalah geoteknik di lapangan.', '<p>Pelatihan Teknik Geoteknik dan Pondasi ini memberikan pemahaman komprehensif tentang perilaku tanah dan perancangan pondasi yang aman dan ekonomis.</p><ol><li>Klasifikasi dan sifat mekanis tanah</li><li>Penyelidikan lapangan dan laboratorium</li><li>Desain pondasi dangkal dan dalam</li><li>Stabilitas lereng dan dinding penahan</li><li>Studi kasus kegagalan geoteknik</li></ol>', 'https://images.unsplash.com/photo-1565793298595-6a879b1d9492?w=800&q=80', '2025-09-15 08:00:00', 'ITB, Bandung', 'https://pii.or.id/pelatihan-geoteknik', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Geoteknik');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('20', 'Konvensi Insinyur Energi Terbarukan Indonesia', 'konferensi', 'Konvensi khusus membahas transisi energi dan peran insinyur dalam mengakselerasi pengembangan energi terbarukan.', '<p>Indonesia memiliki potensi energi terbarukan yang sangat besar — matahari, angin, panas bumi, dan air. Konvensi ini membahas bagaimana insinyur dapat berkontribusi dalam percepatan transisi energi nasional.</p><ul><li>Update kebijakan energi terbarukan 2025</li><li>Teknologi PLTS skala utilitas</li><li>Offshore wind development</li><li>Energy storage solutions</li><li>Peluang karir di sektor EBT</li></ul>', 'https://images.unsplash.com/photo-1509391366360-2e959784a276?w=800&q=80', '2025-11-15 08:00:00', 'Nusa Dua Convention Center, Bali', 'https://pii.or.id/konvensi-ebt-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Energi Terbarukan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('21', 'Seminar Keselamatan Bendungan dan Infrastruktur Air', 'seminar', 'Dengan lebih dari 200 bendungan yang beroperasi di Indonesia, keselamatan bendungan menjadi isu kritis yang harus dipahami setiap insinyur bidang sumber daya air.
Pembicara utama:

Direktur Bendung...', '<p>Dengan lebih dari 200 bendungan yang beroperasi di Indonesia, keselamatan bendungan menjadi isu kritis yang harus dipahami setiap insinyur bidang sumber daya air.</p>
<p><strong>Pembicara utama:</strong></p>
<ul>
<li>Direktur Bendungan Kementerian PUPR</li>
<li>Ahli hidrologi dari UNDIP</li>
<li>Konsultan internasional dari ICOLD</li>
</ul>', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&q=80', '2025-08-28 00:00:00', 'Balai Teknik Sabo, Yogyakarta', 'https://pii.or.id/seminar-bendungan', '1', '2026-05-11 13:01:02', '2026-05-11 13:13:53', 'nasional', 'Sumber Daya Air');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('22', 'Pelatihan Inspeksi dan Pemeliharaan Jembatan', 'pelatihan', 'Pelatihan praktis teknik inspeksi kondisi jembatan dan perencanaan program pemeliharaan yang efektif.', '<p>Indonesia memiliki ribuan jembatan yang perlu diinspeksi dan dipelihara secara berkala. Pelatihan ini membekali insinyur dengan kemampuan inspeksi yang terstandar sesuai Panduan Pemeriksaan Jembatan Kementerian PUPR.</p><ol><li>Sistem klasifikasi kondisi jembatan (BMS)</li><li>Teknik inspeksi visual dan instrumen</li><li>Identifikasi kerusakan beton dan baja</li><li>Perencanaan dan prioritasi pemeliharaan</li></ol>', 'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=800&q=80', '2025-10-14 08:00:00', 'Balai Jembatan, Makassar', NULL, '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'regional', 'Jembatan & Jalan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('23', 'Webinar: Hukum Kontrak untuk Insinyur Lapangan', 'seminar', 'Webinar praktis membahas aspek hukum kontrak konstruksi yang wajib dipahami insinyur di lapangan.', '<p>Banyak insinyur lapangan yang tidak memahami hak dan kewajiban mereka dalam kontrak konstruksi. Webinar ini hadir untuk menjembatani kesenjangan tersebut.</p><p><strong>Topik yang dibahas:</strong></p><ul><li>Jenis-jenis kontrak konstruksi (FIDIC, SBD)</li><li>Hak dan kewajiban kontraktor & owner</li><li>Prosedur klaim dan dispute resolution</li><li>Studi kasus sengketa konstruksi nyata</li></ul>', 'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=800&q=80', '2025-09-10 13:00:00', 'Zoom Webinar (Online)', 'https://zoom.us/pii-kontrak-webinar', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'online', 'Hukum & Regulasi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('24', 'Pelatihan Desain Struktur Baja AISC & SNI', 'pelatihan', 'Pelatihan komprehensif desain struktur baja mengacu standar AISC dan SNI terbaru.', '<p>Struktur baja semakin banyak digunakan dalam konstruksi modern Indonesia. Pelatihan ini memberikan pemahaman mendalam tentang perancangan elemen dan sistem struktur baja.</p><ol><li>Material baja struktural dan sifat mekanisnya</li><li>Desain balok, kolom, dan sambungan baut</li><li>Desain sambungan las</li><li>Pemodelan struktur dengan SAP2000/ETABS</li><li>Aplikasi SNI 1729:2020</li></ol>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2025-12-03 08:00:00', 'Hotel Santika Premiere, Jakarta', 'https://pii.or.id/pelatihan-struktur-baja', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Struktur Baja');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('25', 'Konvensi Insinyur Tambang dan Mineral', 'konferensi', 'Konvensi tahunan insinyur pertambangan membahas isu keberlanjutan, regulasi, dan teknologi terkini industri mining.', '<p>Industri pertambangan Indonesia menghadapi tantangan besar dalam era transisi energi dan tuntutan keberlanjutan. Konvensi ini mempertemukan para pemimpin industri untuk merumuskan arah ke depan.</p><ul><li>Update regulasi pertambangan 2025</li><li>Teknologi mine automation dan digitalisasi</li><li>ESG dalam operasi tambang</li><li>Mine closure dan rehabilitasi lahan</li></ul>', 'https://images.unsplash.com/photo-1578496479531-32e296d5c6e1?w=800&q=80', '2025-11-25 08:00:00', 'Kalimantan Convention Centre, Balikpapan', 'https://pii.or.id/konvensi-tambang-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Pertambangan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('26', 'Workshop GIS untuk Perencanaan Infrastruktur', 'seminar', 'Workshop hands-on penggunaan GIS (Geographic Information System) untuk mendukung perencanaan dan monitoring infrastruktur.', '<p>GIS telah menjadi alat yang tidak terpisahkan dalam perencanaan infrastruktur modern. Workshop ini mengajarkan penggunaan QGIS dan ArcGIS secara praktis untuk aplikasi keinsinyuran.</p><ol><li>Dasar-dasar GIS dan data spasial</li><li>Analisis rute dan transportasi</li><li>Pemetaan risiko bencana</li><li>Monitoring kondisi infrastruktur berbasis GIS</li></ol>', 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=800&q=80', '2025-10-22 08:00:00', 'Institut Teknologi Sepuluh Nopember, Surabaya', 'https://pii.or.id/workshop-gis', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'regional', 'Geospasial & GIS');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('27', 'Pelatihan Pengujian Non-Destruktif (NDT)', 'pelatihan', 'Pelatihan teknik pengujian non-destruktif untuk inspeksi material dan struktur tanpa merusak objek uji.', '<p>Non-Destructive Testing (NDT) adalah kemampuan krusial dalam quality control konstruksi dan inspeksi infrastruktur. Peserta akan mendapatkan sertifikat kompetensi NDT Level 1.</p><ol><li>Ultrasonic Testing (UT)</li><li>Radiographic Testing (RT)</li><li>Magnetic Particle Testing (MT)</li><li>Liquid Penetrant Testing (PT)</li><li>Visual Inspection (VT)</li></ol>', 'https://images.unsplash.com/photo-1581092921461-eab62e97a780?w=800&q=80', '2025-11-04 08:00:00', 'BPPT, Serpong, Tangerang Selatan', 'https://pii.or.id/pelatihan-ndt', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Quality Control');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('28', 'Seminar Nasional Smart City dan Infrastruktur Digital', 'seminar', 'Seminar membahas peran insinyur dalam mewujudkan kota cerdas melalui integrasi teknologi digital dan infrastruktur.', '<p>Lebih dari 100 kota di Indonesia sedang dalam proses transformasi menuju smart city. Seminar ini mendiskusikan tantangan teknis dan peluang bagi insinyur dalam ekosistem kota cerdas.</p><ul><li>Arsitektur sistem smart city</li><li>IoT sensor networks untuk infrastruktur</li><li>Data analytics untuk manajemen kota</li><li>Cybersecurity infrastruktur kritis</li><li>Case study: Surabaya Smart City</li></ul>', 'https://images.unsplash.com/photo-1573164713988-8665fc963095?w=800&q=80', '2025-12-10 09:00:00', 'Balai Kota Surabaya, Surabaya', 'https://pii.or.id/seminar-smart-city', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Smart City');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('29', 'Pelatihan Estimasi Biaya Konstruksi (RAB)', 'pelatihan', 'Pelatihan penyusunan Rencana Anggaran Biaya (RAB) yang akurat dan sesuai standar Permen PUPR terbaru.', '<p>Kesalahan estimasi biaya dapat berakibat fatal bagi keberhasilan proyek. Pelatihan ini memberikan metodologi dan tools praktis untuk menyusun RAB yang akurat.</p><ol><li>Analisa Harga Satuan Pekerjaan (AHSP) terbaru</li><li>Metode volume take-off dari gambar</li><li>Software estimasi: Cubicost dan MS Excel</li><li>Contingency dan eskalasi harga</li><li>Latihan studi kasus proyek nyata</li></ol>', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&q=80', '2025-07-16 08:00:00', 'Hotel Aston, Medan', NULL, '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'regional', 'Cost Engineering');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('30', 'Forum Insinyur Perempuan Indonesia', 'seminar', 'Forum tahunan untuk insinyur perempuan Indonesia membahas tantangan, peluang, dan kepemimpinan di dunia teknik.', '<p>Forum Insinyur Perempuan Indonesia (FIPI) hadir untuk memperkuat peran perempuan dalam ekosistem keinsinyuran nasional. Forum ini menghadirkan role model dan mentor berpengalaman.</p><ul><li>Keynote dari tokoh insinyur perempuan Indonesia</li><li>Panel diskusi: Perempuan di C-Suite industri teknik</li><li>Workshop: Leadership untuk insinyur perempuan</li><li>Mentoring 1-on-1 dengan senior engineer</li></ul>', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=800&q=80', '2025-08-21 09:00:00', 'Hotel Mulia, Jakarta Selatan', 'https://pii.or.id/fipi-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'nasional', 'Diversity & Inclusion');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('31', 'Pelatihan Pemodelan Struktur dengan SAP2000', 'pelatihan', 'Pelatihan online intensif pemodelan dan analisis struktur menggunakan software SAP2000 dari dasar hingga mahir.', '<p>SAP2000 adalah salah satu software analisis struktur paling banyak digunakan di dunia. Pelatihan online ini memungkinkan Anda belajar dari rumah dengan mentor berpengalaman.</p><ol><li>Interface dan setup SAP2000</li><li>Pemodelan frame dan shell element</li><li>Pembebanan: gravitasi, angin, gempa (SNI 1726)</li><li>Analisis statik dan dinamik</li><li>Output dan interpretasi hasil</li><li>Desain elemen dengan code check</li></ol>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', '2025-09-22 09:00:00', 'Zoom Meeting (Online)', 'https://pii.or.id/pelatihan-sap2000', '1', '2026-05-11 13:01:02', '2026-05-11 13:01:02', 'online', 'Structural Analysis Software');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('32', 'Konvensi Insinyur Infrastruktur Transportasi', 'konferensi', 'Indonesia sedang membangun infrastruktur transportasi besar-besaran. Konvensi ini mempertemukan para insinyur dan pemangku kepentingan untuk mendiskusikan inovasi dan tantangan ke depan.

Update pro...', '<p>Indonesia sedang membangun infrastruktur transportasi besar-besaran. Konvensi ini mempertemukan para insinyur dan pemangku kepentingan untuk mendiskusikan inovasi dan tantangan ke depan.</p>
<ul>
<li>Update proyek strategis nasional (PSN) transportasi</li>
<li>Teknologi konstruksi jalan tol terkini</li>
<li>High-speed rail engineering</li>
<li>Pengembangan pelabuhan dan bandara</li>
<li>Integrasi moda transportasi</li>
<li>Sesi bilateral dengan delegasi asing</li>
</ul>', 'https://images.unsplash.com/photo-1474487548417-781cb71495f3?w=800&q=80', '2025-12-17 00:00:00', 'Jakarta International Expo, Jakarta', 'https://pii.or.id/konvensi-transportasi-2025', '1', '2026-05-11 13:01:02', '2026-05-11 13:13:46', 'internasional', 'Transportasi & Mobilitas');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('35', 'Seminar Nasional Keinsinyuran 2025', 'seminar', 'Seminar nasional membahas peran insinyur dalam pembangunan infrastruktur berkelanjutan di Indonesia.', '<p>Seminar Nasional Keinsinyuran 2025 akan menghadirkan para pakar dan praktisi terkemuka di bidang keinsinyuran untuk membahas isu-isu strategis dalam pembangunan infrastruktur Indonesia.</p><p><strong>Topik yang akan dibahas:</strong></p><ul><li>Infrastruktur hijau dan berkelanjutan</li><li>Digitalisasi dalam dunia konstruksi</li><li>Standar keselamatan bangunan terkini</li></ul>', NULL, '2025-08-15 09:00:00', 'Jakarta Convention Center, Jakarta', 'https://pii.or.id/seminar-nasional-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Infrastruktur & Pembangunan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('36', 'Pelatihan BIM (Building Information Modeling) Level 1', 'pelatihan', 'Pelatihan intensif BIM untuk insinyur sipil dan arsitek yang ingin meningkatkan kompetensi digital mereka.', '<p>Pelatihan BIM Level 1 dirancang khusus untuk para profesional di bidang konstruksi yang ingin memahami dan mengimplementasikan Building Information Modeling dalam proyek mereka.</p><p><strong>Materi Pelatihan:</strong></p><ol><li>Pengenalan dan konsep dasar BIM</li><li>Software Revit untuk pemula</li><li>Kolaborasi tim berbasis BIM</li><li>Studi kasus proyek nyata</li></ol>', NULL, '2025-09-05 08:00:00', 'Gedung PII, Menteng, Jakarta Pusat', 'https://pii.or.id/pelatihan-bim-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Teknologi Konstruksi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('37', 'Konvensi Insinyur Internasional Asia Pacific 2025', 'konferensi', 'Konvensi tahunan insinyur se-Asia Pacific membahas tantangan dan peluang di era revolusi industri 4.0.', '<p>Konvensi Insinyur Internasional Asia Pacific 2025 merupakan ajang bergengsi yang mempertemukan para insinyur dari seluruh kawasan Asia Pacific.</p><p>Tahun ini mengangkat tema <strong>\"Engineering for a Sustainable Future\"</strong> dengan fokus pada:</p><ul><li>Energi terbarukan dan transisi energi</li><li>Smart city dan infrastruktur digital</li><li>Ketahanan terhadap perubahan iklim</li><li>Kolaborasi riset antar negara</li></ul>', NULL, '2025-10-20 08:00:00', 'Bali International Convention Centre, Bali', 'https://pii.or.id/konvensi-internasional-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'internasional', 'Asia Pacific Engineering Forum');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('38', 'Pelatihan K3 (Keselamatan dan Kesehatan Kerja) untuk Insinyur', 'pelatihan', 'Pelatihan K3 wajib bagi insinyur yang bekerja di lapangan untuk memastikan standar keselamatan kerja terpenuhi.', '<p>Keselamatan dan Kesehatan Kerja (K3) adalah aspek fundamental yang tidak boleh diabaikan oleh setiap insinyur lapangan. Pelatihan ini memberikan pemahaman komprehensif tentang regulasi K3 terbaru di Indonesia.</p><p><strong>Jadwal Pelatihan:</strong></p><ol><li>Hari 1: Regulasi K3 dan standar internasional</li><li>Hari 2: Identifikasi bahaya dan penilaian risiko</li><li>Hari 3: Praktik lapangan dan simulasi</li></ol>', NULL, '2025-07-10 08:00:00', 'Hotel Santika, Surabaya', NULL, '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regional', 'Keselamatan Kerja');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('39', 'Webinar: Transformasi Digital di Industri Manufaktur Indonesia', 'seminar', 'Webinar gratis membahas bagaimana insinyur manufaktur dapat beradaptasi dengan era digitalisasi industri.', '<p>Di era Industri 4.0, transformasi digital bukan lagi pilihan melainkan keharusan. Webinar ini akan membahas strategi dan langkah konkret bagi para insinyur manufaktur untuk menavigasi perubahan tersebut.</p><p><strong>Pembicara:</strong></p><ul><li>Ir. Budi Santoso, M.Eng - Direktur PT. Industri Nusantara</li><li>Dr. Siti Rahayu - Peneliti BRIN bidang Manufaktur Digital</li></ul><p>Webinar ini <strong>GRATIS</strong> untuk anggota PII aktif.</p>', NULL, '2025-06-25 13:00:00', 'Zoom Meeting (Online)', 'https://zoom.us/pii-webinar-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'online', 'Industri 4.0');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('40', 'Pelatihan Sertifikasi Insinyur Profesional (IP)', 'pelatihan', 'Program persiapan sertifikasi Insinyur Profesional (IP) untuk anggota PII yang ingin meningkatkan jenjang karir.', '<p>Sertifikasi Insinyur Profesional (IP) adalah pengakuan resmi atas kompetensi seorang insinyur dalam bidangnya. Program pelatihan ini dirancang untuk mempersiapkan peserta menghadapi ujian sertifikasi IP.</p><p><strong>Modul Pelatihan:</strong></p><ol><li>Etika profesi keinsinyuran</li><li>Standar dan regulasi teknis</li><li>Manajemen proyek engineering</li><li>Simulasi soal ujian IP</li><li>Sesi tanya jawab dengan penguji bersertifikat</li></ol><p>Peserta yang lulus akan mendapatkan <strong>sertifikat keikutsertaan</strong> dan dapat langsung mendaftar ujian IP resmi PII.</p>', NULL, '2025-11-08 08:00:00', 'Graha PII, Jakarta Selatan', 'https://pii.or.id/sertifikasi-ip-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Sertifikasi & Kompetensi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('41', 'Workshop Inovasi Infrastruktur Hijau', 'seminar', 'Workshop membahas pendekatan terbaru dalam pembangunan infrastruktur yang ramah lingkungan dan berkelanjutan.', '<p>Workshop ini menghadirkan para pakar infrastruktur hijau dari seluruh Indonesia untuk berbagi pengetahuan dan praktik terbaik dalam membangun infrastruktur yang berkelanjutan.</p><ul><li>Green building standards dan sertifikasi</li><li>Material konstruksi ramah lingkungan</li><li>Manajemen energi pada bangunan</li><li>Studi kasus proyek sukses</li></ul>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2025-07-22 08:00:00', 'Bandung Convention Centre, Bandung', 'https://pii.or.id/workshop-infrastruktur-hijau', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Infrastruktur Berkelanjutan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('42', 'Pelatihan Manajemen Proyek Konstruksi Level Lanjut', 'pelatihan', 'Pelatihan intensif 3 hari untuk meningkatkan kemampuan manajemen proyek konstruksi skala besar.', '<p>Program pelatihan lanjutan ini dirancang untuk insinyur berpengalaman yang ingin meningkatkan kompetensi dalam mengelola proyek konstruksi skala besar dan kompleks.</p><ol><li>Advanced scheduling dengan Primavera P6</li><li>Risk management dalam proyek konstruksi</li><li>Contract management dan klaim</li><li>Leadership dan team management</li></ol>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2025-08-12 08:00:00', 'Hotel Pullman, Jakarta Pusat', 'https://pii.or.id/pelatihan-pm-lanjut', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Project Management');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('43', 'Konvensi Tahunan Insinyur Sipil Indonesia 2025', 'konferensi', 'Konvensi tahunan untuk insinyur sipil membahas perkembangan terkini teknologi dan standar konstruksi.', '<p>Konvensi Tahunan Insinyur Sipil Indonesia 2025 adalah forum bergengsi yang mempertemukan ribuan insinyur sipil dari seluruh nusantara.</p><p>Tema tahun ini: <strong>\"Resilient Infrastructure for Indonesia 2045\"</strong></p><ul><li>Keynote dari Menteri PUPR</li><li>Panel diskusi pembangunan IKN</li><li>Pameran teknologi konstruksi terbaru</li><li>Networking session</li></ul>', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', '2025-09-18 08:00:00', 'Surabaya Convention Hall, Surabaya', 'https://pii.or.id/konvensi-sipil-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Teknik Sipil');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('44', 'Webinar: AI dan Machine Learning untuk Insinyur', 'seminar', 'Webinar gratis mengenai penerapan AI dan machine learning dalam berbagai bidang keinsinyuran.', '<p>Di era kecerdasan buatan, insinyur perlu memahami bagaimana AI dapat digunakan untuk meningkatkan efisiensi dan akurasi pekerjaan mereka.</p><p><strong>Yang akan dibahas:</strong></p><ul><li>Pengantar AI dan ML untuk non-programmer</li><li>Computer vision dalam inspeksi infrastruktur</li><li>Predictive maintenance dengan ML</li><li>Tools AI yang bisa langsung digunakan</li></ul>', 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=800&q=80', '2025-07-30 14:00:00', 'Google Meet (Online)', 'https://meet.google.com/pii-ai-webinar', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'online', 'Artificial Intelligence');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('45', 'Pelatihan AutoCAD & Revit untuk Insinyur Mekanikal', 'pelatihan', 'Pelatihan software desain AutoCAD dan Revit khusus untuk insinyur di bidang mekanikal dan elektrikal.', '<p>Kuasai dua software desain paling populer di industri konstruksi dan manufaktur. Pelatihan ini mencakup dasar hingga tingkat mahir dalam penggunaan AutoCAD dan Revit untuk aplikasi mekanikal.</p><ol><li>AutoCAD 2D fundamentals</li><li>AutoCAD 3D modelling</li><li>Revit MEP basics</li><li>Koordinasi antar disiplin dengan BIM</li></ol>', 'https://images.unsplash.com/photo-1581092918056-0c4c3acd3789?w=800&q=80', '2025-08-05 08:00:00', 'Pusat Pelatihan PII, Semarang', NULL, '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regional', 'CAD & BIM');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('46', 'Forum Insinyur Muda Indonesia 2025', 'seminar', 'Forum tahunan khusus untuk insinyur muda berusia di bawah 35 tahun untuk berjejaring dan berbagi ide.', '<p>Forum Insinyur Muda Indonesia (FIMI) 2025 adalah ruang bagi generasi insinyur muda untuk saling terhubung, berbagi gagasan inovatif, dan merumuskan kontribusi nyata bagi kemajuan bangsa.</p><p><strong>Highlight acara:</strong></p><ul><li>Pitch kompetisi inovasi teknik</li><li>Mentoring dengan senior insinyur</li><li>Career development workshop</li><li>Networking dengan perusahaan top</li></ul>', 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800&q=80', '2025-10-04 08:00:00', 'Universitas Indonesia, Depok', 'https://pii.or.id/fimi-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Young Engineers');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('47', 'Pelatihan Teknik Geoteknik dan Pondasi', 'pelatihan', 'Pelatihan mendalam mengenai analisis tanah, desain pondasi, dan penanganan masalah geoteknik di lapangan.', '<p>Pelatihan Teknik Geoteknik dan Pondasi ini memberikan pemahaman komprehensif tentang perilaku tanah dan perancangan pondasi yang aman dan ekonomis.</p><ol><li>Klasifikasi dan sifat mekanis tanah</li><li>Penyelidikan lapangan dan laboratorium</li><li>Desain pondasi dangkal dan dalam</li><li>Stabilitas lereng dan dinding penahan</li><li>Studi kasus kegagalan geoteknik</li></ol>', 'https://images.unsplash.com/photo-1565793298595-6a879b1d9492?w=800&q=80', '2025-09-15 08:00:00', 'ITB, Bandung', 'https://pii.or.id/pelatihan-geoteknik', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Geoteknik');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('48', 'Konvensi Insinyur Energi Terbarukan Indonesia', 'konferensi', 'Konvensi khusus membahas transisi energi dan peran insinyur dalam mengakselerasi pengembangan energi terbarukan.', '<p>Indonesia memiliki potensi energi terbarukan yang sangat besar — matahari, angin, panas bumi, dan air. Konvensi ini membahas bagaimana insinyur dapat berkontribusi dalam percepatan transisi energi nasional.</p><ul><li>Update kebijakan energi terbarukan 2025</li><li>Teknologi PLTS skala utilitas</li><li>Offshore wind development</li><li>Energy storage solutions</li><li>Peluang karir di sektor EBT</li></ul>', 'https://images.unsplash.com/photo-1509391366360-2e959784a276?w=800&q=80', '2025-11-15 08:00:00', 'Nusa Dua Convention Center, Bali', 'https://pii.or.id/konvensi-ebt-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Energi Terbarukan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('49', 'Seminar Keselamatan Bendungan dan Infrastruktur Air', 'seminar', 'Seminar teknis tentang keselamatan bendungan, pengelolaan risiko banjir, dan infrastruktur air bersih.', '<p>Dengan lebih dari 200 bendungan yang beroperasi di Indonesia, keselamatan bendungan menjadi isu kritis yang harus dipahami setiap insinyur bidang sumber daya air.</p><p><strong>Pembicara utama:</strong></p><ul><li>Direktur Bendungan Kementerian PUPR</li><li>Ahli hidrologi dari UNDIP</li><li>Konsultan internasional dari ICOLD</li></ul>', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&q=80', '2025-08-28 09:00:00', 'Balai Teknik Sabo, Yogyakarta', 'https://pii.or.id/seminar-bendungan', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Sumber Daya Air');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('50', 'Pelatihan Inspeksi dan Pemeliharaan Jembatan', 'pelatihan', 'Pelatihan praktis teknik inspeksi kondisi jembatan dan perencanaan program pemeliharaan yang efektif.', '<p>Indonesia memiliki ribuan jembatan yang perlu diinspeksi dan dipelihara secara berkala. Pelatihan ini membekali insinyur dengan kemampuan inspeksi yang terstandar sesuai Panduan Pemeriksaan Jembatan Kementerian PUPR.</p><ol><li>Sistem klasifikasi kondisi jembatan (BMS)</li><li>Teknik inspeksi visual dan instrumen</li><li>Identifikasi kerusakan beton dan baja</li><li>Perencanaan dan prioritasi pemeliharaan</li></ol>', 'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=800&q=80', '2025-10-14 08:00:00', 'Balai Jembatan, Makassar', NULL, '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regional', 'Jembatan & Jalan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('51', 'Webinar: Hukum Kontrak untuk Insinyur Lapangan', 'seminar', 'Webinar praktis membahas aspek hukum kontrak konstruksi yang wajib dipahami insinyur di lapangan.', '<p>Banyak insinyur lapangan yang tidak memahami hak dan kewajiban mereka dalam kontrak konstruksi. Webinar ini hadir untuk menjembatani kesenjangan tersebut.</p><p><strong>Topik yang dibahas:</strong></p><ul><li>Jenis-jenis kontrak konstruksi (FIDIC, SBD)</li><li>Hak dan kewajiban kontraktor & owner</li><li>Prosedur klaim dan dispute resolution</li><li>Studi kasus sengketa konstruksi nyata</li></ul>', 'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=800&q=80', '2025-09-10 13:00:00', 'Zoom Webinar (Online)', 'https://zoom.us/pii-kontrak-webinar', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'online', 'Hukum & Regulasi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('52', 'Pelatihan Desain Struktur Baja AISC & SNI', 'pelatihan', 'Pelatihan komprehensif desain struktur baja mengacu standar AISC dan SNI terbaru.', '<p>Struktur baja semakin banyak digunakan dalam konstruksi modern Indonesia. Pelatihan ini memberikan pemahaman mendalam tentang perancangan elemen dan sistem struktur baja.</p><ol><li>Material baja struktural dan sifat mekanisnya</li><li>Desain balok, kolom, dan sambungan baut</li><li>Desain sambungan las</li><li>Pemodelan struktur dengan SAP2000/ETABS</li><li>Aplikasi SNI 1729:2020</li></ol>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2025-12-03 08:00:00', 'Hotel Santika Premiere, Jakarta', 'https://pii.or.id/pelatihan-struktur-baja', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Struktur Baja');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('53', 'Konvensi Insinyur Tambang dan Mineral', 'konferensi', 'Konvensi tahunan insinyur pertambangan membahas isu keberlanjutan, regulasi, dan teknologi terkini industri mining.', '<p>Industri pertambangan Indonesia menghadapi tantangan besar dalam era transisi energi dan tuntutan keberlanjutan. Konvensi ini mempertemukan para pemimpin industri untuk merumuskan arah ke depan.</p><ul><li>Update regulasi pertambangan 2025</li><li>Teknologi mine automation dan digitalisasi</li><li>ESG dalam operasi tambang</li><li>Mine closure dan rehabilitasi lahan</li></ul>', 'https://images.unsplash.com/photo-1578496479531-32e296d5c6e1?w=800&q=80', '2025-11-25 08:00:00', 'Kalimantan Convention Centre, Balikpapan', 'https://pii.or.id/konvensi-tambang-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Pertambangan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('54', 'Workshop GIS untuk Perencanaan Infrastruktur', 'seminar', 'Workshop hands-on penggunaan GIS (Geographic Information System) untuk mendukung perencanaan dan monitoring infrastruktur.', '<p>GIS telah menjadi alat yang tidak terpisahkan dalam perencanaan infrastruktur modern. Workshop ini mengajarkan penggunaan QGIS dan ArcGIS secara praktis untuk aplikasi keinsinyuran.</p><ol><li>Dasar-dasar GIS dan data spasial</li><li>Analisis rute dan transportasi</li><li>Pemetaan risiko bencana</li><li>Monitoring kondisi infrastruktur berbasis GIS</li></ol>', 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=800&q=80', '2025-10-22 08:00:00', 'Institut Teknologi Sepuluh Nopember, Surabaya', 'https://pii.or.id/workshop-gis', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regional', 'Geospasial & GIS');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('55', 'Pelatihan Pengujian Non-Destruktif (NDT)', 'pelatihan', 'Pelatihan teknik pengujian non-destruktif untuk inspeksi material dan struktur tanpa merusak objek uji.', '<p>Non-Destructive Testing (NDT) adalah kemampuan krusial dalam quality control konstruksi dan inspeksi infrastruktur. Peserta akan mendapatkan sertifikat kompetensi NDT Level 1.</p><ol><li>Ultrasonic Testing (UT)</li><li>Radiographic Testing (RT)</li><li>Magnetic Particle Testing (MT)</li><li>Liquid Penetrant Testing (PT)</li><li>Visual Inspection (VT)</li></ol>', 'https://images.unsplash.com/photo-1581092921461-eab62e97a780?w=800&q=80', '2025-11-04 08:00:00', 'BPPT, Serpong, Tangerang Selatan', 'https://pii.or.id/pelatihan-ndt', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Quality Control');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('56', 'Seminar Nasional Smart City dan Infrastruktur Digital', 'seminar', 'Seminar membahas peran insinyur dalam mewujudkan kota cerdas melalui integrasi teknologi digital dan infrastruktur.', '<p>Lebih dari 100 kota di Indonesia sedang dalam proses transformasi menuju smart city. Seminar ini mendiskusikan tantangan teknis dan peluang bagi insinyur dalam ekosistem kota cerdas.</p><ul><li>Arsitektur sistem smart city</li><li>IoT sensor networks untuk infrastruktur</li><li>Data analytics untuk manajemen kota</li><li>Cybersecurity infrastruktur kritis</li><li>Case study: Surabaya Smart City</li></ul>', 'https://images.unsplash.com/photo-1573164713988-8665fc963095?w=800&q=80', '2025-12-10 09:00:00', 'Balai Kota Surabaya, Surabaya', 'https://pii.or.id/seminar-smart-city', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Smart City');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('57', 'Pelatihan Estimasi Biaya Konstruksi (RAB)', 'pelatihan', 'Pelatihan penyusunan Rencana Anggaran Biaya (RAB) yang akurat dan sesuai standar Permen PUPR terbaru.', '<p>Kesalahan estimasi biaya dapat berakibat fatal bagi keberhasilan proyek. Pelatihan ini memberikan metodologi dan tools praktis untuk menyusun RAB yang akurat.</p><ol><li>Analisa Harga Satuan Pekerjaan (AHSP) terbaru</li><li>Metode volume take-off dari gambar</li><li>Software estimasi: Cubicost dan MS Excel</li><li>Contingency dan eskalasi harga</li><li>Latihan studi kasus proyek nyata</li></ol>', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&q=80', '2025-07-16 08:00:00', 'Hotel Aston, Medan', NULL, '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'regional', 'Cost Engineering');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('58', 'Forum Insinyur Perempuan Indonesia', 'seminar', 'Forum tahunan untuk insinyur perempuan Indonesia membahas tantangan, peluang, dan kepemimpinan di dunia teknik.', '<p>Forum Insinyur Perempuan Indonesia (FIPI) hadir untuk memperkuat peran perempuan dalam ekosistem keinsinyuran nasional. Forum ini menghadirkan role model dan mentor berpengalaman.</p><ul><li>Keynote dari tokoh insinyur perempuan Indonesia</li><li>Panel diskusi: Perempuan di C-Suite industri teknik</li><li>Workshop: Leadership untuk insinyur perempuan</li><li>Mentoring 1-on-1 dengan senior engineer</li></ul>', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=800&q=80', '2025-08-21 09:00:00', 'Hotel Mulia, Jakarta Selatan', 'https://pii.or.id/fipi-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Diversity & Inclusion');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('59', 'Pelatihan Pemodelan Struktur dengan SAP2000', 'pelatihan', 'Pelatihan online intensif pemodelan dan analisis struktur menggunakan software SAP2000 dari dasar hingga mahir.', '<p>SAP2000 adalah salah satu software analisis struktur paling banyak digunakan di dunia. Pelatihan online ini memungkinkan Anda belajar dari rumah dengan mentor berpengalaman.</p><ol><li>Interface dan setup SAP2000</li><li>Pemodelan frame dan shell element</li><li>Pembebanan: gravitasi, angin, gempa (SNI 1726)</li><li>Analisis statik dan dinamik</li><li>Output dan interpretasi hasil</li><li>Desain elemen dengan code check</li></ol>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', '2025-09-22 09:00:00', 'Zoom Meeting (Online)', 'https://pii.or.id/pelatihan-sap2000', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'online', 'Structural Analysis Software');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('60', 'Konvensi Insinyur Infrastruktur Transportasi', 'konferensi', 'Konvensi internasional membahas masa depan infrastruktur transportasi — jalan tol, kereta cepat, dan pelabuhan.', '<p>Indonesia sedang membangun infrastruktur transportasi besar-besaran. Konvensi ini mempertemukan para insinyur dan pemangku kepentingan untuk mendiskusikan inovasi dan tantangan ke depan.</p><ul><li>Update proyek strategis nasional (PSN) transportasi</li><li>Teknologi konstruksi jalan tol terkini</li><li>High-speed rail engineering</li><li>Pengembangan pelabuhan dan bandara</li><li>Integrasi moda transportasi</li><li>Sesi bilateral dengan delegasi asing</li></ul>', 'https://images.unsplash.com/photo-1474487548417-781cb71495f3?w=800&q=80', '2025-12-17 08:00:00', 'Jakarta International Expo, Jakarta', 'https://pii.or.id/konvensi-transportasi-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'internasional', 'Transportasi & Mobilitas');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('61', 'Pelatihan Lean Construction untuk Proyek Efisien', 'pelatihan', 'Pelatihan metodologi Lean Construction untuk mengurangi waste dan meningkatkan efisiensi proyek.', '<p>Lean Construction adalah metodologi yang fokus pada minimasi waste dan maksimasi nilai dalam proyek konstruksi. Pelatihan ini mengajarkan prinsip dan tools Lean.</p><ol><li>Last Planner System</li><li>Value Stream Mapping</li><li>Target Value Design</li><li>Choosing by Advantages</li><li>Implementasi Lean di proyek nyata</li></ol>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2025-07-18 08:00:00', 'Hotel Grand Hyatt, Jakarta', 'https://pii.or.id/pelatihan-lean-construction', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Project Management');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('62', 'Seminar Teknologi Beton High-Performance', 'seminar', 'Seminar membahas perkembangan teknologi beton high-performance untuk struktur modern.', '<p>Beton high-performance (HPC) semakin banyak digunakan dalam proyek-proyek strategis Indonesia. Seminar ini membahas teknologi terbaru dan aplikasinya.</p><p><strong>Topik utama:</strong></p><ul><li>Self-compacting concrete (SCC)</li><li>Ultra-high performance concrete (UHPC)</li><li>Fiber-reinforced concrete</li><li>Durability dan life-cycle</li></ul>', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', '2025-08-30 09:00:00', 'Universitas Gadjah Mada, Yogyakarta', 'https://pii.or.id/seminar-beton-hpc', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Material Konstruksi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('63', 'Webinar: Blockchain untuk Supply Chain Konstruksi', 'seminar', 'Webinar gratis membahas potensi blockchain dalam transparansi dan efisiensi supply chain konstruksi.', '<p>Blockchain technology menawarkan potensi besar untuk meningkatkan transparansi dan efisiensi dalam supply chain konstruksi.</p><p><strong>Yang akan dibahas:</strong></p><ul><li>Dasar blockchain untuk non-teknis</li><li>Smart contracts dalam konstruksi</li><li>Tracking material dan quality assurance</li><li>Studi kasus implementasi</li></ul>', 'https://images.unsplash.com/photo-1639762681485-074b7f938ba0?w=800&q=80', '2025-09-25 14:00:00', 'Zoom Meeting (Online)', 'https://zoom.us/pii-blockchain-webinar', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'online', 'Teknologi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('64', 'Pelatihan Leadership untuk Insinyur Project Manager', 'pelatihan', 'Pelatihan leadership khusus untuk insinyur yang ingin menjadi project manager yang efektif.', '<p>Technical skills saja tidak cukup untuk menjadi project manager sukses. Pelatihan ini membekali insinyur dengan leadership skills yang diperlukan.</p><ol><li>Komunikasi efektif dengan stakeholder</li><li>Conflict resolution dalam tim</li><li>Decision making under pressure</li><li>Building high-performing teams</li><li>Emotional intelligence untuk leader</li></ol>', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=800&q=80', '2025-10-08 08:00:00', 'Hotel Mulia, Jakarta', 'https://pii.or.id/pelatihan-leadership-pm', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Leadership');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('65', 'Konvensi Insinyur Telekomunikasi Indonesia', 'konferensi', 'Konvensi tahunan insinyur telekomunikasi membahas perkembangan 5G dan infrastruktur digital.', '<p>Indonesia sedang mempercepat rollout 5G dan pengembangan infrastruktur digital nasional. Konvensi ini membahas tantangan teknis dan peluang bagi insinyur telekomunikasi.</p><ul><li>5G network architecture</li><li>Fiber optic deployment</li><li>Data center infrastructure</li><li>Satellite communication</li><li>Cybersecurity telecom networks</li></ul>', 'https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800&q=80', '2025-11-20 08:00:00', 'Telkom HQ, Bandung', 'https://pii.or.id/konvensi-telekomunikasi-2025', '1', '2026-05-11 13:40:33', '2026-05-11 13:40:33', 'nasional', 'Telekomunikasi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('66', 'Seminar Nasional Keinsinyuran 2025', 'seminar', 'Seminar nasional membahas peran insinyur dalam pembangunan infrastruktur berkelanjutan di Indonesia.', '<p>Seminar Nasional Keinsinyuran 2025 akan menghadirkan para pakar dan praktisi terkemuka di bidang keinsinyuran untuk membahas isu-isu strategis dalam pembangunan infrastruktur Indonesia.</p><p><strong>Topik yang akan dibahas:</strong></p><ul><li>Infrastruktur hijau dan berkelanjutan</li><li>Digitalisasi dalam dunia konstruksi</li><li>Standar keselamatan bangunan terkini</li></ul>', NULL, '2025-08-15 09:00:00', 'Jakarta Convention Center, Jakarta', 'https://pii.or.id/seminar-nasional-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Infrastruktur & Pembangunan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('67', 'Pelatihan BIM (Building Information Modeling) Level 1', 'pelatihan', 'Pelatihan intensif BIM untuk insinyur sipil dan arsitek yang ingin meningkatkan kompetensi digital mereka.', '<p>Pelatihan BIM Level 1 dirancang khusus untuk para profesional di bidang konstruksi yang ingin memahami dan mengimplementasikan Building Information Modeling dalam proyek mereka.</p><p><strong>Materi Pelatihan:</strong></p><ol><li>Pengenalan dan konsep dasar BIM</li><li>Software Revit untuk pemula</li><li>Kolaborasi tim berbasis BIM</li><li>Studi kasus proyek nyata</li></ol>', NULL, '2025-09-05 08:00:00', 'Gedung PII, Menteng, Jakarta Pusat', 'https://pii.or.id/pelatihan-bim-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Teknologi Konstruksi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('68', 'Konvensi Insinyur Internasional Asia Pacific 2025', 'konferensi', 'Konvensi tahunan insinyur se-Asia Pacific membahas tantangan dan peluang di era revolusi industri 4.0.', '<p>Konvensi Insinyur Internasional Asia Pacific 2025 merupakan ajang bergengsi yang mempertemukan para insinyur dari seluruh kawasan Asia Pacific.</p><p>Tahun ini mengangkat tema <strong>\"Engineering for a Sustainable Future\"</strong> dengan fokus pada:</p><ul><li>Energi terbarukan dan transisi energi</li><li>Smart city dan infrastruktur digital</li><li>Ketahanan terhadap perubahan iklim</li><li>Kolaborasi riset antar negara</li></ul>', NULL, '2025-10-20 08:00:00', 'Bali International Convention Centre, Bali', 'https://pii.or.id/konvensi-internasional-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'internasional', 'Asia Pacific Engineering Forum');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('69', 'Pelatihan K3 (Keselamatan dan Kesehatan Kerja) untuk Insinyur', 'pelatihan', 'Pelatihan K3 wajib bagi insinyur yang bekerja di lapangan untuk memastikan standar keselamatan kerja terpenuhi.', '<p>Keselamatan dan Kesehatan Kerja (K3) adalah aspek fundamental yang tidak boleh diabaikan oleh setiap insinyur lapangan. Pelatihan ini memberikan pemahaman komprehensif tentang regulasi K3 terbaru di Indonesia.</p><p><strong>Jadwal Pelatihan:</strong></p><ol><li>Hari 1: Regulasi K3 dan standar internasional</li><li>Hari 2: Identifikasi bahaya dan penilaian risiko</li><li>Hari 3: Praktik lapangan dan simulasi</li></ol>', NULL, '2025-07-10 08:00:00', 'Hotel Santika, Surabaya', NULL, '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'regional', 'Keselamatan Kerja');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('70', 'Webinar: Transformasi Digital di Industri Manufaktur Indonesia', 'seminar', 'Webinar gratis membahas bagaimana insinyur manufaktur dapat beradaptasi dengan era digitalisasi industri.', '<p>Di era Industri 4.0, transformasi digital bukan lagi pilihan melainkan keharusan. Webinar ini akan membahas strategi dan langkah konkret bagi para insinyur manufaktur untuk menavigasi perubahan tersebut.</p><p><strong>Pembicara:</strong></p><ul><li>Ir. Budi Santoso, M.Eng - Direktur PT. Industri Nusantara</li><li>Dr. Siti Rahayu - Peneliti BRIN bidang Manufaktur Digital</li></ul><p>Webinar ini <strong>GRATIS</strong> untuk anggota PII aktif.</p>', NULL, '2025-06-25 13:00:00', 'Zoom Meeting (Online)', 'https://zoom.us/pii-webinar-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'online', 'Industri 4.0');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('71', 'Pelatihan Sertifikasi Insinyur Profesional (IP)', 'pelatihan', 'Program persiapan sertifikasi Insinyur Profesional (IP) untuk anggota PII yang ingin meningkatkan jenjang karir.', '<p>Sertifikasi Insinyur Profesional (IP) adalah pengakuan resmi atas kompetensi seorang insinyur dalam bidangnya. Program pelatihan ini dirancang untuk mempersiapkan peserta menghadapi ujian sertifikasi IP.</p><p><strong>Modul Pelatihan:</strong></p><ol><li>Etika profesi keinsinyuran</li><li>Standar dan regulasi teknis</li><li>Manajemen proyek engineering</li><li>Simulasi soal ujian IP</li><li>Sesi tanya jawab dengan penguji bersertifikat</li></ol><p>Peserta yang lulus akan mendapatkan <strong>sertifikat keikutsertaan</strong> dan dapat langsung mendaftar ujian IP resmi PII.</p>', NULL, '2025-11-08 08:00:00', 'Graha PII, Jakarta Selatan', 'https://pii.or.id/sertifikasi-ip-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Sertifikasi & Kompetensi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('72', 'Workshop Inovasi Infrastruktur Hijau', 'seminar', 'Workshop membahas pendekatan terbaru dalam pembangunan infrastruktur yang ramah lingkungan dan berkelanjutan.', '<p>Workshop ini menghadirkan para pakar infrastruktur hijau dari seluruh Indonesia untuk berbagi pengetahuan dan praktik terbaik dalam membangun infrastruktur yang berkelanjutan.</p><ul><li>Green building standards dan sertifikasi</li><li>Material konstruksi ramah lingkungan</li><li>Manajemen energi pada bangunan</li><li>Studi kasus proyek sukses</li></ul>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2025-07-22 08:00:00', 'Bandung Convention Centre, Bandung', 'https://pii.or.id/workshop-infrastruktur-hijau', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Infrastruktur Berkelanjutan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('73', 'Pelatihan Manajemen Proyek Konstruksi Level Lanjut', 'pelatihan', 'Pelatihan intensif 3 hari untuk meningkatkan kemampuan manajemen proyek konstruksi skala besar.', '<p>Program pelatihan lanjutan ini dirancang untuk insinyur berpengalaman yang ingin meningkatkan kompetensi dalam mengelola proyek konstruksi skala besar dan kompleks.</p><ol><li>Advanced scheduling dengan Primavera P6</li><li>Risk management dalam proyek konstruksi</li><li>Contract management dan klaim</li><li>Leadership dan team management</li></ol>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2025-08-12 08:00:00', 'Hotel Pullman, Jakarta Pusat', 'https://pii.or.id/pelatihan-pm-lanjut', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Project Management');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('74', 'Konvensi Tahunan Insinyur Sipil Indonesia 2025', 'konferensi', 'Konvensi tahunan untuk insinyur sipil membahas perkembangan terkini teknologi dan standar konstruksi.', '<p>Konvensi Tahunan Insinyur Sipil Indonesia 2025 adalah forum bergengsi yang mempertemukan ribuan insinyur sipil dari seluruh nusantara.</p><p>Tema tahun ini: <strong>\"Resilient Infrastructure for Indonesia 2045\"</strong></p><ul><li>Keynote dari Menteri PUPR</li><li>Panel diskusi pembangunan IKN</li><li>Pameran teknologi konstruksi terbaru</li><li>Networking session</li></ul>', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', '2025-09-18 08:00:00', 'Surabaya Convention Hall, Surabaya', 'https://pii.or.id/konvensi-sipil-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Teknik Sipil');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('75', 'Webinar: AI dan Machine Learning untuk Insinyur', 'seminar', 'Webinar gratis mengenai penerapan AI dan machine learning dalam berbagai bidang keinsinyuran.', '<p>Di era kecerdasan buatan, insinyur perlu memahami bagaimana AI dapat digunakan untuk meningkatkan efisiensi dan akurasi pekerjaan mereka.</p><p><strong>Yang akan dibahas:</strong></p><ul><li>Pengantar AI dan ML untuk non-programmer</li><li>Computer vision dalam inspeksi infrastruktur</li><li>Predictive maintenance dengan ML</li><li>Tools AI yang bisa langsung digunakan</li></ul>', 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=800&q=80', '2025-07-30 14:00:00', 'Google Meet (Online)', 'https://meet.google.com/pii-ai-webinar', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'online', 'Artificial Intelligence');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('76', 'Pelatihan AutoCAD & Revit untuk Insinyur Mekanikal', 'pelatihan', 'Pelatihan software desain AutoCAD dan Revit khusus untuk insinyur di bidang mekanikal dan elektrikal.', '<p>Kuasai dua software desain paling populer di industri konstruksi dan manufaktur. Pelatihan ini mencakup dasar hingga tingkat mahir dalam penggunaan AutoCAD dan Revit untuk aplikasi mekanikal.</p><ol><li>AutoCAD 2D fundamentals</li><li>AutoCAD 3D modelling</li><li>Revit MEP basics</li><li>Koordinasi antar disiplin dengan BIM</li></ol>', 'https://images.unsplash.com/photo-1581092918056-0c4c3acd3789?w=800&q=80', '2025-08-05 08:00:00', 'Pusat Pelatihan PII, Semarang', NULL, '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'regional', 'CAD & BIM');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('77', 'Forum Insinyur Muda Indonesia 2025', 'seminar', 'Forum tahunan khusus untuk insinyur muda berusia di bawah 35 tahun untuk berjejaring dan berbagi ide.', '<p>Forum Insinyur Muda Indonesia (FIMI) 2025 adalah ruang bagi generasi insinyur muda untuk saling terhubung, berbagi gagasan inovatif, dan merumuskan kontribusi nyata bagi kemajuan bangsa.</p><p><strong>Highlight acara:</strong></p><ul><li>Pitch kompetisi inovasi teknik</li><li>Mentoring dengan senior insinyur</li><li>Career development workshop</li><li>Networking dengan perusahaan top</li></ul>', 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800&q=80', '2025-10-04 08:00:00', 'Universitas Indonesia, Depok', 'https://pii.or.id/fimi-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Young Engineers');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('78', 'Pelatihan Teknik Geoteknik dan Pondasi', 'pelatihan', 'Pelatihan mendalam mengenai analisis tanah, desain pondasi, dan penanganan masalah geoteknik di lapangan.', '<p>Pelatihan Teknik Geoteknik dan Pondasi ini memberikan pemahaman komprehensif tentang perilaku tanah dan perancangan pondasi yang aman dan ekonomis.</p><ol><li>Klasifikasi dan sifat mekanis tanah</li><li>Penyelidikan lapangan dan laboratorium</li><li>Desain pondasi dangkal dan dalam</li><li>Stabilitas lereng dan dinding penahan</li><li>Studi kasus kegagalan geoteknik</li></ol>', 'https://images.unsplash.com/photo-1565793298595-6a879b1d9492?w=800&q=80', '2025-09-15 08:00:00', 'ITB, Bandung', 'https://pii.or.id/pelatihan-geoteknik', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Geoteknik');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('79', 'Konvensi Insinyur Energi Terbarukan Indonesia', 'konferensi', 'Konvensi khusus membahas transisi energi dan peran insinyur dalam mengakselerasi pengembangan energi terbarukan.', '<p>Indonesia memiliki potensi energi terbarukan yang sangat besar — matahari, angin, panas bumi, dan air. Konvensi ini membahas bagaimana insinyur dapat berkontribusi dalam percepatan transisi energi nasional.</p><ul><li>Update kebijakan energi terbarukan 2025</li><li>Teknologi PLTS skala utilitas</li><li>Offshore wind development</li><li>Energy storage solutions</li><li>Peluang karir di sektor EBT</li></ul>', 'https://images.unsplash.com/photo-1509391366360-2e959784a276?w=800&q=80', '2025-11-15 08:00:00', 'Nusa Dua Convention Center, Bali', 'https://pii.or.id/konvensi-ebt-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Energi Terbarukan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('80', 'Seminar Keselamatan Bendungan dan Infrastruktur Air', 'seminar', 'Seminar teknis tentang keselamatan bendungan, pengelolaan risiko banjir, dan infrastruktur air bersih.', '<p>Dengan lebih dari 200 bendungan yang beroperasi di Indonesia, keselamatan bendungan menjadi isu kritis yang harus dipahami setiap insinyur bidang sumber daya air.</p><p><strong>Pembicara utama:</strong></p><ul><li>Direktur Bendungan Kementerian PUPR</li><li>Ahli hidrologi dari UNDIP</li><li>Konsultan internasional dari ICOLD</li></ul>', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=800&q=80', '2025-08-28 09:00:00', 'Balai Teknik Sabo, Yogyakarta', 'https://pii.or.id/seminar-bendungan', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Sumber Daya Air');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('81', 'Pelatihan Inspeksi dan Pemeliharaan Jembatan', 'pelatihan', 'Pelatihan praktis teknik inspeksi kondisi jembatan dan perencanaan program pemeliharaan yang efektif.', '<p>Indonesia memiliki ribuan jembatan yang perlu diinspeksi dan dipelihara secara berkala. Pelatihan ini membekali insinyur dengan kemampuan inspeksi yang terstandar sesuai Panduan Pemeriksaan Jembatan Kementerian PUPR.</p><ol><li>Sistem klasifikasi kondisi jembatan (BMS)</li><li>Teknik inspeksi visual dan instrumen</li><li>Identifikasi kerusakan beton dan baja</li><li>Perencanaan dan prioritasi pemeliharaan</li></ol>', 'https://images.unsplash.com/photo-1477959858617-67f85cf4f1df?w=800&q=80', '2025-10-14 08:00:00', 'Balai Jembatan, Makassar', NULL, '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'regional', 'Jembatan & Jalan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('82', 'Webinar: Hukum Kontrak untuk Insinyur Lapangan', 'seminar', 'Webinar praktis membahas aspek hukum kontrak konstruksi yang wajib dipahami insinyur di lapangan.', '<p>Banyak insinyur lapangan yang tidak memahami hak dan kewajiban mereka dalam kontrak konstruksi. Webinar ini hadir untuk menjembatani kesenjangan tersebut.</p><p><strong>Topik yang dibahas:</strong></p><ul><li>Jenis-jenis kontrak konstruksi (FIDIC, SBD)</li><li>Hak dan kewajiban kontraktor & owner</li><li>Prosedur klaim dan dispute resolution</li><li>Studi kasus sengketa konstruksi nyata</li></ul>', 'https://images.unsplash.com/photo-1589829545856-d10d557cf95f?w=800&q=80', '2025-09-10 13:00:00', 'Zoom Webinar (Online)', 'https://zoom.us/pii-kontrak-webinar', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'online', 'Hukum & Regulasi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('83', 'Pelatihan Desain Struktur Baja AISC & SNI', 'pelatihan', 'Pelatihan komprehensif desain struktur baja mengacu standar AISC dan SNI terbaru.', '<p>Struktur baja semakin banyak digunakan dalam konstruksi modern Indonesia. Pelatihan ini memberikan pemahaman mendalam tentang perancangan elemen dan sistem struktur baja.</p><ol><li>Material baja struktural dan sifat mekanisnya</li><li>Desain balok, kolom, dan sambungan baut</li><li>Desain sambungan las</li><li>Pemodelan struktur dengan SAP2000/ETABS</li><li>Aplikasi SNI 1729:2020</li></ol>', 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=800&q=80', '2025-12-03 08:00:00', 'Hotel Santika Premiere, Jakarta', 'https://pii.or.id/pelatihan-struktur-baja', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Struktur Baja');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('84', 'Konvensi Insinyur Tambang dan Mineral', 'konferensi', 'Konvensi tahunan insinyur pertambangan membahas isu keberlanjutan, regulasi, dan teknologi terkini industri mining.', '<p>Industri pertambangan Indonesia menghadapi tantangan besar dalam era transisi energi dan tuntutan keberlanjutan. Konvensi ini mempertemukan para pemimpin industri untuk merumuskan arah ke depan.</p><ul><li>Update regulasi pertambangan 2025</li><li>Teknologi mine automation dan digitalisasi</li><li>ESG dalam operasi tambang</li><li>Mine closure dan rehabilitasi lahan</li></ul>', 'https://images.unsplash.com/photo-1578496479531-32e296d5c6e1?w=800&q=80', '2025-11-25 08:00:00', 'Kalimantan Convention Centre, Balikpapan', 'https://pii.or.id/konvensi-tambang-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Pertambangan');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('85', 'Workshop GIS untuk Perencanaan Infrastruktur', 'seminar', 'Workshop hands-on penggunaan GIS (Geographic Information System) untuk mendukung perencanaan dan monitoring infrastruktur.', '<p>GIS telah menjadi alat yang tidak terpisahkan dalam perencanaan infrastruktur modern. Workshop ini mengajarkan penggunaan QGIS dan ArcGIS secara praktis untuk aplikasi keinsinyuran.</p><ol><li>Dasar-dasar GIS dan data spasial</li><li>Analisis rute dan transportasi</li><li>Pemetaan risiko bencana</li><li>Monitoring kondisi infrastruktur berbasis GIS</li></ol>', 'https://images.unsplash.com/photo-1524661135-423995f22d0b?w=800&q=80', '2025-10-22 08:00:00', 'Institut Teknologi Sepuluh Nopember, Surabaya', 'https://pii.or.id/workshop-gis', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'regional', 'Geospasial & GIS');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('86', 'Pelatihan Pengujian Non-Destruktif (NDT)', 'pelatihan', 'Pelatihan teknik pengujian non-destruktif untuk inspeksi material dan struktur tanpa merusak objek uji.', '<p>Non-Destructive Testing (NDT) adalah kemampuan krusial dalam quality control konstruksi dan inspeksi infrastruktur. Peserta akan mendapatkan sertifikat kompetensi NDT Level 1.</p><ol><li>Ultrasonic Testing (UT)</li><li>Radiographic Testing (RT)</li><li>Magnetic Particle Testing (MT)</li><li>Liquid Penetrant Testing (PT)</li><li>Visual Inspection (VT)</li></ol>', 'https://images.unsplash.com/photo-1581092921461-eab62e97a780?w=800&q=80', '2025-11-04 08:00:00', 'BPPT, Serpong, Tangerang Selatan', 'https://pii.or.id/pelatihan-ndt', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Quality Control');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('87', 'Seminar Nasional Smart City dan Infrastruktur Digital', 'seminar', 'Seminar membahas peran insinyur dalam mewujudkan kota cerdas melalui integrasi teknologi digital dan infrastruktur.', '<p>Lebih dari 100 kota di Indonesia sedang dalam proses transformasi menuju smart city. Seminar ini mendiskusikan tantangan teknis dan peluang bagi insinyur dalam ekosistem kota cerdas.</p><ul><li>Arsitektur sistem smart city</li><li>IoT sensor networks untuk infrastruktur</li><li>Data analytics untuk manajemen kota</li><li>Cybersecurity infrastruktur kritis</li><li>Case study: Surabaya Smart City</li></ul>', 'https://images.unsplash.com/photo-1573164713988-8665fc963095?w=800&q=80', '2025-12-10 09:00:00', 'Balai Kota Surabaya, Surabaya', 'https://pii.or.id/seminar-smart-city', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Smart City');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('88', 'Pelatihan Estimasi Biaya Konstruksi (RAB)', 'pelatihan', 'Pelatihan penyusunan Rencana Anggaran Biaya (RAB) yang akurat dan sesuai standar Permen PUPR terbaru.', '<p>Kesalahan estimasi biaya dapat berakibat fatal bagi keberhasilan proyek. Pelatihan ini memberikan metodologi dan tools praktis untuk menyusun RAB yang akurat.</p><ol><li>Analisa Harga Satuan Pekerjaan (AHSP) terbaru</li><li>Metode volume take-off dari gambar</li><li>Software estimasi: Cubicost dan MS Excel</li><li>Contingency dan eskalasi harga</li><li>Latihan studi kasus proyek nyata</li></ol>', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=800&q=80', '2025-07-16 08:00:00', 'Hotel Aston, Medan', NULL, '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'regional', 'Cost Engineering');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('89', 'Forum Insinyur Perempuan Indonesia', 'seminar', 'Forum tahunan untuk insinyur perempuan Indonesia membahas tantangan, peluang, dan kepemimpinan di dunia teknik.', '<p>Forum Insinyur Perempuan Indonesia (FIPI) hadir untuk memperkuat peran perempuan dalam ekosistem keinsinyuran nasional. Forum ini menghadirkan role model dan mentor berpengalaman.</p><ul><li>Keynote dari tokoh insinyur perempuan Indonesia</li><li>Panel diskusi: Perempuan di C-Suite industri teknik</li><li>Workshop: Leadership untuk insinyur perempuan</li><li>Mentoring 1-on-1 dengan senior engineer</li></ul>', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=800&q=80', '2025-08-21 09:00:00', 'Hotel Mulia, Jakarta Selatan', 'https://pii.or.id/fipi-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Diversity & Inclusion');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('90', 'Pelatihan Pemodelan Struktur dengan SAP2000', 'pelatihan', 'Pelatihan online intensif pemodelan dan analisis struktur menggunakan software SAP2000 dari dasar hingga mahir.', '<p>SAP2000 adalah salah satu software analisis struktur paling banyak digunakan di dunia. Pelatihan online ini memungkinkan Anda belajar dari rumah dengan mentor berpengalaman.</p><ol><li>Interface dan setup SAP2000</li><li>Pemodelan frame dan shell element</li><li>Pembebanan: gravitasi, angin, gempa (SNI 1726)</li><li>Analisis statik dan dinamik</li><li>Output dan interpretasi hasil</li><li>Desain elemen dengan code check</li></ol>', 'https://images.unsplash.com/photo-1551288049-bebda4e38f71?w=800&q=80', '2025-09-22 09:00:00', 'Zoom Meeting (Online)', 'https://pii.or.id/pelatihan-sap2000', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'online', 'Structural Analysis Software');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('91', 'Konvensi Insinyur Infrastruktur Transportasi', 'konferensi', 'Konvensi internasional membahas masa depan infrastruktur transportasi — jalan tol, kereta cepat, dan pelabuhan.', '<p>Indonesia sedang membangun infrastruktur transportasi besar-besaran. Konvensi ini mempertemukan para insinyur dan pemangku kepentingan untuk mendiskusikan inovasi dan tantangan ke depan.</p><ul><li>Update proyek strategis nasional (PSN) transportasi</li><li>Teknologi konstruksi jalan tol terkini</li><li>High-speed rail engineering</li><li>Pengembangan pelabuhan dan bandara</li><li>Integrasi moda transportasi</li><li>Sesi bilateral dengan delegasi asing</li></ul>', 'https://images.unsplash.com/photo-1474487548417-781cb71495f3?w=800&q=80', '2025-12-17 08:00:00', 'Jakarta International Expo, Jakarta', 'https://pii.or.id/konvensi-transportasi-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'internasional', 'Transportasi & Mobilitas');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('92', 'Pelatihan Lean Construction untuk Proyek Efisien', 'pelatihan', 'Pelatihan metodologi Lean Construction untuk mengurangi waste dan meningkatkan efisiensi proyek.', '<p>Lean Construction adalah metodologi yang fokus pada minimasi waste dan maksimasi nilai dalam proyek konstruksi. Pelatihan ini mengajarkan prinsip dan tools Lean.</p><ol><li>Last Planner System</li><li>Value Stream Mapping</li><li>Target Value Design</li><li>Choosing by Advantages</li><li>Implementasi Lean di proyek nyata</li></ol>', 'https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=800&q=80', '2025-07-18 08:00:00', 'Hotel Grand Hyatt, Jakarta', 'https://pii.or.id/pelatihan-lean-construction', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Project Management');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('93', 'Seminar Teknologi Beton High-Performance', 'seminar', 'Seminar membahas perkembangan teknologi beton high-performance untuk struktur modern.', '<p>Beton high-performance (HPC) semakin banyak digunakan dalam proyek-proyek strategis Indonesia. Seminar ini membahas teknologi terbaru dan aplikasinya.</p><p><strong>Topik utama:</strong></p><ul><li>Self-compacting concrete (SCC)</li><li>Ultra-high performance concrete (UHPC)</li><li>Fiber-reinforced concrete</li><li>Durability dan life-cycle</li></ul>', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80', '2025-08-30 09:00:00', 'Universitas Gadjah Mada, Yogyakarta', 'https://pii.or.id/seminar-beton-hpc', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Material Konstruksi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('94', 'Webinar: Blockchain untuk Supply Chain Konstruksi', 'seminar', 'Webinar gratis membahas potensi blockchain dalam transparansi dan efisiensi supply chain konstruksi.', '<p>Blockchain technology menawarkan potensi besar untuk meningkatkan transparansi dan efisiensi dalam supply chain konstruksi.</p><p><strong>Yang akan dibahas:</strong></p><ul><li>Dasar blockchain untuk non-teknis</li><li>Smart contracts dalam konstruksi</li><li>Tracking material dan quality assurance</li><li>Studi kasus implementasi</li></ul>', 'https://images.unsplash.com/photo-1639762681485-074b7f938ba0?w=800&q=80', '2025-09-25 14:00:00', 'Zoom Meeting (Online)', 'https://zoom.us/pii-blockchain-webinar', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'online', 'Teknologi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('95', 'Pelatihan Leadership untuk Insinyur Project Manager', 'pelatihan', 'Pelatihan leadership khusus untuk insinyur yang ingin menjadi project manager yang efektif.', '<p>Technical skills saja tidak cukup untuk menjadi project manager sukses. Pelatihan ini membekali insinyur dengan leadership skills yang diperlukan.</p><ol><li>Komunikasi efektif dengan stakeholder</li><li>Conflict resolution dalam tim</li><li>Decision making under pressure</li><li>Building high-performing teams</li><li>Emotional intelligence untuk leader</li></ol>', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=800&q=80', '2025-10-08 08:00:00', 'Hotel Mulia, Jakarta', 'https://pii.or.id/pelatihan-leadership-pm', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Leadership');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('96', 'Konvensi Insinyur Telekomunikasi Indonesia', 'konferensi', 'Konvensi tahunan insinyur telekomunikasi membahas perkembangan 5G dan infrastruktur digital.', '<p>Indonesia sedang mempercepat rollout 5G dan pengembangan infrastruktur digital nasional. Konvensi ini membahas tantangan teknis dan peluang bagi insinyur telekomunikasi.</p><ul><li>5G network architecture</li><li>Fiber optic deployment</li><li>Data center infrastructure</li><li>Satellite communication</li><li>Cybersecurity telecom networks</li></ul>', 'https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=800&q=80', '2025-11-20 08:00:00', 'Telkom HQ, Bandung', 'https://pii.or.id/konvensi-telekomunikasi-2025', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Telekomunikasi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('97', 'World Engineering Forum 2026', 'konferensi', 'Forum engineering dunia membahas solusi global untuk tantangan iklim dan energi.', '<p>World Engineering Forum 2026 akan menghadirkan pemimpin engineering dari seluruh dunia untuk membahas solusi kolaboratif terhadap tantangan global.</p><ul><li>Climate adaptation engineering</li><li>Global energy transition</li><li>Sustainable infrastructure</li><li>International collaboration frameworks</li></ul>', 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=800&q=80', '2026-03-15 08:00:00', 'Singapore Expo, Singapore', 'https://wef2026.global', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'internasional', 'Global Engineering');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('98', 'Pelatihan AI untuk Insinyur Konstruksi', 'pelatihan', 'Pelatihan ini dirancang untuk insinyur konstruksi yang ingin mengadopsi teknologi AI dalam pekerjaan sehari-hari.

Computer vision untuk inspeksi
Predictive maintenance
AI untuk scheduling proyek...', '<p>Pelatihan ini dirancang untuk insinyur konstruksi yang ingin mengadopsi teknologi AI dalam pekerjaan sehari-hari.</p>
<ol>
<li>Computer vision untuk inspeksi</li>
<li>Predictive maintenance</li>
<li>AI untuk scheduling proyek</li>
<li>Machine learning untuk estimasi biaya</li>
</ol>', 'https://images.unsplash.com/photo-1677442136071-1787eea5ce01?w=800&q=80', '2026-04-10 00:00:00', 'Training Center PII, Jakarta', 'https://pii.or.id/pelatihan-ai-konstruksi', '0', '2026-05-11 13:47:40', '2026-05-12 05:52:15', 'nasional', 'Artificial Intelligence');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('99', 'Seminar: Future of Smart Cities in Indonesia', 'seminar', 'Seminar membahas visi Indonesia menuju 100 smart city pada 2030.', '<p>Indonesia menargetkan 100 smart city pada 2030. Seminar ini membahas roadmap dan implementasi teknologi yang diperlukan.</p><ul><li>IoT infrastructure</li><li>Smart transportation systems</li><li>Digital governance</li><li>Public-private partnerships</li></ul>', 'https://images.unsplash.com/photo-1573164713988-8665fc963095?w=800&q=80', '2026-05-22 09:00:00', 'Balai Kota Jakarta, Jakarta', 'https://pii.or.id/seminar-smart-city-2026', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Smart City');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('100', 'Pelatihan Cybersecurity untuk Critical Infrastructure', 'pelatihan', 'Pelatihan keamanan siber untuk insinyur yang mengelola infrastruktur kritis.', '<p>Infrastruktur kritis seperti PLN, pertamina, dan transportasi membutuhkan proteksi siber yang kuat. Pelatihan ini membahas best practices.</p><ol><li>Threat assessment</li><li>Incident response</li><li>Secure system design</li><li>Compliance and regulations</li></ol>', 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b?w=800&q=80', '2026-06-18 08:00:00', 'Cybersecurity Training Center, BSD City', 'https://pii.or.id/pelatihan-cybersec', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Cybersecurity');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('101', 'Konvensi Insinyur Lingkungan Asia Pasifik', 'konferensi', 'Konvensi regional membahas solusi engineering untuk isu lingkungan Asia Pasifik.', '<p>Konvensi ini mempertemukan insinyur lingkungan dari seluruh Asia Pasifik untuk berbagi solusi terbaik dalam penanganan isu lingkungan.</p><ul><li>Wastewater treatment innovation</li><li>Air quality management</li><li>Solid waste solutions</li><li>Climate resilience engineering</li></ul>', 'https://images.unsplash.com/photo-1497436072909-60f360e1d4b1?w=800&q=80', '2026-07-20 08:00:00', 'Bali Nusa Dua Convention Center, Bali', 'https://apiee2026.org', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'internasional', 'Environmental Engineering');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('102', 'Webinar: Quantum Computing untuk Insinyur', 'seminar', 'Webinar pengenalan quantum computing dan potensi aplikasinya dalam engineering.', '<p>Quantum computing akan mengubah landscape engineering dalam dekade mendatang. Webinar ini memberikan pengantar untuk insinyur.</p><p><strong>Topik:</strong></p><ul><li>Quantum basics for engineers</li><li>Quantum algorithms for optimization</li><li>Applications in materials science</li><li>Future prospects</li></ul>', 'https://images.unsplash.com/photo-1635070041078-e363dbe005cb?w=800&q=80', '2026-08-15 14:00:00', 'Zoom Webinar (Online)', 'https://zoom.us/pii-quantum', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'online', 'Quantum Technology');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('103', 'Pelatihan Project Management Digital', 'pelatihan', 'Pelatihan manajemen proyek berbasis digital dengan tools modern.', '<p>Manajemen proyek modern membutuhkan tools digital untuk efisiensi maksimal. Pelatihan ini mengajarkan penggunaan berbagai PM tools.</p><ol><li>Jira and Confluence</li><li>Microsoft Project Online</li><li>Asana for engineering projects</li><li>Collaboration platforms</li></ol>', 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=800&q=80', '2026-09-12 08:00:00', 'Digital Training Hub, Jakarta', 'https://pii.or.id/pelatihan-digital-pm', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Digital PM');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('104', 'Seminar: Hydrogen Economy dan Peran Insinyur', 'seminar', 'Seminar membahas ekonomi hidrogen dan peluang bagi insinyur Indonesia.', '<p>Hidrogen hijau adalah masa depan energi bersih. Seminar ini membahas peluang dan tantangan dalam ekonomi hidrogen Indonesia.</p><ul><li>Green hydrogen production</li><li>Infrastructure requirements</li><li>Policy and regulations</li><li>Career opportunities in hydrogen sector</li></ul>', 'https://images.unsplash.com/photo-1597424456583-7a2b637aeb49?w=800&q=80', '2026-10-25 09:00:00', 'Energy Building, Jakarta', 'https://pii.or.id/seminar-hydrogen', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Energi');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('105', 'Pelatihan 3D Printing untuk Konstruksi', 'pelatihan', 'Pelatihan teknologi 3D printing dalam konstruksi dan manufaktur.', '<p>3D printing atau additive manufacturing mengubah cara kita membangun. Pelatihan ini mengajarkan aplikasi praktis dalam konstruksi.</p><ol><li>Concrete 3D printing</li><li>Material selection</li><li>Design for additive manufacturing</li><li>Case studies and hands-on</li></ol>', 'https://images.unsplash.com/photo-1563872263814-8a549ea66981?w=800&q=80', '2026-11-08 08:00:00', 'Advanced Manufacturing Lab, Bandung', 'https://pii.or.id/pelatihan-3d-printing', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Advanced Manufacturing');
INSERT INTO `events` (`id`, `title`, `type`, `description`, `content`, `image`, `event_date`, `location`, `link`, `is_active`, `created_at`, `updated_at`, `category`, `sub_category`) VALUES ('106', 'Konvensi Insinyur Masa Depan 2027', 'konferensi', 'Konvensi visioner membahas masa depan profesi keinsinyuran Indonesia 2045.', '<p>Konvensi ini merumuskan visi dan strategi profesi keinsinyuran Indonesia menuju Golden Indonesia 2045.</p><ul><li>Engineering education transformation</li><li>Skill requirements for 2045</li><li>Industry 5.0 readiness</li><li>Sustainable development goals</li><li>Youth leadership development</li></ul>', 'https://images.unsplash.com/photo-1517245386807-bb43f82c33c4?w=800&q=80', '2027-01-20 08:00:00', 'Indonesia Convention Exhibition, Jakarta', 'https://pii.or.id/konvensi-future-2027', '1', '2026-05-11 13:47:40', '2026-05-11 13:47:40', 'nasional', 'Future Engineering');

DROP TABLE IF EXISTS `kontaks`;
CREATE TABLE `kontaks` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `address` VARCHAR(255) not null, `phone` VARCHAR(255) not null, `email` VARCHAR(255) not null, `facebook` VARCHAR(255), `twitter` VARCHAR(255), `instagram` VARCHAR(255), `linkedin` VARCHAR(255), `youtube` VARCHAR(255), `map_url` text, `is_active` tinyint(1) not null default ('1'), `created_at` datetime, `updated_at` datetime);

