DROP TABLE IF EXISTS `struktur_kepengurusans`;
CREATE TABLE `struktur_kepengurusans` (`id` INT PRIMARY KEY AUTO_INCREMENT not null, `title` VARCHAR(255), `content` text, `image` VARCHAR(255), `is_active` tinyint(1) not null default '1', `created_at` datetime, `updated_at` datetime);

INSERT INTO `struktur_kepengurusans` (`id`, `title`, `content`, `image`, `is_active`, `created_at`, `updated_at`) VALUES ('1', 'Kepengurusan', '<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Ketua Umum:</strong>&nbsp;Dr.-Ing.Ir. Ilham Akbar Habibie, MBA., IPU.</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Wakil Ketua Umum:</strong>&nbsp;Prof. Dr. Ir. Agus Taufik Mulyono, ST., MT., IPU., ASEAN Eng.</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Kepala Satuan Pengawas Internal:</strong>&nbsp;Dr. Ir. Abdullah Qiqi Asmara, S.T., M.Si., M.Kom., IPU</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Sekretaris Jendral:</strong>&nbsp;Dr. Ir. Teguh Haryono, MBA., IPU., ACPE., ASEAN Eng., APEC Eng.</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Bendahara Umum:</strong>&nbsp;Ir. Hilmi Panigoro, MBA., MSc</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Direktur Eksekutif:</strong>&nbsp;Ir. Santhi H. Serad, M.Sc., IPU.</p>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Wakil Sekretaris Jenderal</strong></p>
<ol class=\"my-1 pl-6 list-decimal [&amp;&gt;li]:mt-2 [&amp;&gt;li]:text-sm list-outside !list-decimal\">
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"1\">Wakil Sekretaris Jenderal 1: Ir. Sri Hidayat AKP, ST, M.Sc(PM)., IPU, APEC Eng., ASEAN Eng.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"2\">Wakil Sekretaris Jenderal 2: Dr. Ir. D. Viby Indrayana, ST, MM, MT, IPU, ASEAN Eng.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"3\">Wakil Sekretaris Jenderal 3: Dr. Ir. Gunawan Adji, MT.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"4\">Wakil Sekretaris Jenderal 4: Ir. Luki Danardi, ST., M.Eng., IPM., ASEAN Eng.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"5\">Wakil Sekretaris Jenderal 5: Ir. Ellys Kusuma Laksanawati, ST., MT., IPM., ASEAN Eng.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"6\">Wakil Sekretaris Jenderal 6: Ir. Haudhi Ramadhayuza, ST., IPM.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"7\">Wakil Sekretaris Jenderal 7: Ir, Panji Sukma Nugraha, ST. MM.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"8\">Wakil Sekretaris Jenderal 8: Ir. Willy Sakareza, ST., M.Sc., IPM.</li>
</ol>
<p class=\"leading-7 text-sm py-1\" dir=\"ltr\"><strong class=\"font-bold\">Wakil Bendahara Umum</strong></p>
<ol class=\"my-1 pl-6 list-decimal [&amp;&gt;li]:mt-2 [&amp;&gt;li]:text-sm list-outside !list-decimal\">
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"1\">Wakil Bendahara Umum 1: Sri Hartono Indrijanto, ST.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"2\">Wakil Bendahara Umum 2: Ir. Fandi Wijaya, ST., IPU.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"3\">Wakil Bendahara Umum 3: Dr. Ir. Izhari Mawardi, B.Eng (Hons)., S.AP., MPP., IPU., ASEAN Eng.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"4\">Wakil Bendahara Umum 4: Ir. Moeharmein Zein Chaniago, M.Eng.</li>
<li class=\"mx-8 text-sm\" dir=\"ltr\" value=\"5\">Wakil Bendahara Umum 5: Ir. Rahmat Yudianto, IPU</li>
